"use client";

import { useEffect, useMemo, useState } from "react";
import Link from "next/link";
import { Loader2, PlusCircle, ArrowRight, FileText, CheckCircle2, DollarSign, AlertTriangle, TrendingUp, RefreshCw, Clock, Activity, BarChart3, Shield } from "lucide-react";
import ProtectedRoute from "@/components/protected-route";
import { useAuth } from "@/context/auth-context";
import { usePermissions } from "@/hooks/usePermissions";
import { getQuotesV3 } from "@/lib/api";
import { API_BASE_URL } from "@/lib/config";
import type { V3QuoteComputeResponse } from "@/lib/types";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { QuoteStatusBadge } from "@/components/QuoteStatusBadge";

const formatCurrency = (value: number, currency = "PGK") =>
  new Intl.NumberFormat("en-US", {
    style: "currency",
    currency,
    maximumFractionDigits: 0,
  }).format(value || 0);

interface FxStatusData {
  rates: Array<{ currency: string; tt_buy: string; tt_sell: string }>;
  last_updated: string | null;
  source: string | null;
  is_stale: boolean;
  staleness_hours: number | null;
  staleness_warning: string | null;
}

export default function HomePage() {
  const { user } = useAuth();
  const { isFinance, canEditQuotes } = usePermissions();
  const [allQuotes, setAllQuotes] = useState<V3QuoteComputeResponse[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [fxStatus, setFxStatus] = useState<FxStatusData | null>(null);
  const [fxLoading, setFxLoading] = useState(false);

  useEffect(() => {
    if (!user) {
      return;
    }
    const fetchQuotes = async () => {
      setLoading(true);
      setError(null);
      try {
        const data = await getQuotesV3();
        setAllQuotes(data.results);
      } catch (err: unknown) {
        const message =
          err instanceof Error ? err.message : "Unable to load quotes.";
        setError(message);
      } finally {
        setLoading(false);
      }
    };
    fetchQuotes();
  }, [user]);

  // Fetch FX status for Finance users
  useEffect(() => {
    if (!user || !isFinance) return;

    const fetchFxStatus = async () => {
      setFxLoading(true);
      try {
        const token = localStorage.getItem('authToken');
        const response = await fetch(`${API_BASE_URL}/api/v4/fx/status/`, {
          headers: {
            'Authorization': token ? `Token ${token}` : '',
            'Content-Type': 'application/json',
          },
        });
        if (response.ok) {
          const data = await response.json();
          setFxStatus(data);
        }
      } catch (err) {
        console.error('Failed to fetch FX status:', err);
      } finally {
        setFxLoading(false);
      }
    };
    fetchFxStatus();
  }, [user, isFinance]);

  // Metrics calculations
  const metrics = useMemo(() => {
    const draftQuotes = allQuotes.filter(q => q.status?.toLowerCase() === 'draft');
    const finalizedQuotes = allQuotes.filter(q => q.status?.toLowerCase() === 'finalized');
    const sentQuotes = allQuotes.filter(q => q.status?.toLowerCase() === 'sent');
    const approvedQuotes = allQuotes.filter(q => q.status?.toLowerCase() === 'approved');
    const cancelledQuotes = allQuotes.filter(q => q.status?.toLowerCase() === 'cancelled');

    const currency = allQuotes[0]?.latest_version.totals.total_sell_fcy_currency ?? "PGK";

    // Total value of finalized quotes
    const finalizedValue = finalizedQuotes.reduce((sum, quote) => {
      const amount = parseFloat(quote.latest_version.totals.total_sell_fcy_incl_gst || "0");
      return sum + (isNaN(amount) ? 0 : amount);
    }, 0);

    // Pipeline value (all non-cancelled)
    const pipelineValue = allQuotes
      .filter(q => q.status?.toLowerCase() !== 'cancelled')
      .reduce((sum, quote) => {
        const amount = parseFloat(quote.latest_version.totals.total_sell_fcy_incl_gst || "0");
        return sum + (isNaN(amount) ? 0 : amount);
      }, 0);

    return {
      draftCount: draftQuotes.length,
      finalizedCount: finalizedQuotes.length,
      sentCount: sentQuotes.length,
      approvedCount: approvedQuotes.length,
      cancelledCount: cancelledQuotes.length,
      totalQuotes: allQuotes.length,
      finalizedValue,
      pipelineValue,
      currency,
    };
  }, [allQuotes]);

  const recentQuotes = useMemo(() => allQuotes.slice(0, 5), [allQuotes]);

  const renderRecentQuotes = () => {
    if (loading) {
      return (
        <div className="flex items-center justify-center py-12 text-muted-foreground">
          <Loader2 className="mr-2 h-5 w-5 animate-spin" />
          <span className="text-sm">Loading quotes...</span>
        </div>
      );
    }

    if (error) {
      return (
        <Alert variant="destructive">
          <AlertTitle>Something went wrong</AlertTitle>
          <AlertDescription>{error}</AlertDescription>
        </Alert>
      );
    }

    if (recentQuotes.length === 0) {
      return (
        <div className="flex flex-col items-center justify-center gap-3 py-12 text-center text-muted-foreground">
          <FileText className="h-12 w-12 opacity-30" />
          <p className="text-sm">No quotes available.</p>
        </div>
      );
    }

    return (
      <div className="overflow-hidden">
        <Table>
          <TableHeader>
            <TableRow className="bg-muted/30 hover:bg-muted/30">
              <TableHead className="font-semibold">Quote #</TableHead>
              <TableHead className="font-semibold">Route</TableHead>
              <TableHead className="font-semibold">Status</TableHead>
              <TableHead className="text-right font-semibold">Total (inc. GST)</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {recentQuotes.map((quote) => (
              <TableRow
                key={quote.id}
                className="cursor-pointer hover:bg-primary/5 transition-colors"
                onClick={() => window.location.href = `/quotes/${quote.id}`}
              >
                <TableCell>
                  <span className="text-primary font-semibold hover:underline">
                    {quote.quote_number}
                  </span>
                </TableCell>
                <TableCell className="text-muted-foreground">
                  {quote.origin_location}
                  <span className="mx-2 text-muted-foreground/50">→</span>
                  {quote.destination_location}
                </TableCell>
                <TableCell>
                  <QuoteStatusBadge status={quote.status} />
                </TableCell>
                <TableCell className="text-right font-semibold tabular-nums">
                  {formatCurrency(
                    parseFloat(quote.latest_version.totals.total_sell_fcy_incl_gst || "0"),
                    quote.latest_version.totals.total_sell_fcy_currency,
                  )}
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>
    );
  };

  const displayName = user?.username;

  // ========== FINANCE DASHBOARD ==========
  if (isFinance) {
    // Finance-specific metrics (PGK only)
    const now = new Date();
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();

    // Filter finalized quotes for current month
    const finalizedThisMonth = allQuotes.filter(q => {
      if (q.status?.toLowerCase() !== 'finalized') return false;
      const createdAt = new Date(q.created_at);
      return createdAt.getMonth() === currentMonth && createdAt.getFullYear() === currentYear;
    });

    // Finalized Revenue in PGK
    const finalizedRevenuePGK = finalizedThisMonth.reduce((sum, quote) => {
      const amount = parseFloat(quote.latest_version.totals.total_sell_pgk_incl_gst || quote.latest_version.totals.total_sell_fcy_incl_gst || "0");
      return sum + (isNaN(amount) ? 0 : amount);
    }, 0);

    // Draft quotes only for pipeline
    const draftQuotes = allQuotes.filter(q => q.status?.toLowerCase() === 'draft');
    const pipelinePGK = draftQuotes.reduce((sum, quote) => {
      const amount = parseFloat(quote.latest_version.totals.total_sell_pgk_incl_gst || quote.latest_version.totals.total_sell_fcy_incl_gst || "0");
      return sum + (isNaN(amount) ? 0 : amount);
    }, 0);

    // Helper to format route as "City (CODE)"
    const formatRoute = (location: string): string => {
      if (!location) return '';
      const match = location.match(/^([A-Z]{3})\s*-\s*(.+)$/);
      if (match) {
        const [, code, fullName] = match;
        const cityName = fullName.replace(/\s+(Airport|Intl|International|Jacksons|Terminal|Apt).*$/i, '').trim();
        return `${cityName} (${code})`;
      }
      return location;
    };

    // Helper to format mode
    const formatMode = (mode: string): string => {
      const modeMap: Record<string, string> = {
        'AIR': 'Air Freight', 'air': 'Air Freight',
        'SEA': 'Sea Freight', 'sea': 'Sea Freight',
        'INLAND': 'Inland Transport', 'inland': 'Inland Transport',
        'ROAD': 'Inland Transport', 'road': 'Inland Transport',
      };
      return modeMap[mode] || mode;
    };

    // Helper to get customer name
    const getCustomerName = (customer: typeof allQuotes[0]['customer']): string => {
      if (typeof customer === 'string') return customer;
      return customer?.company_name || customer?.name || 'Unknown';
    };

    // Helper to format status text
    const formatStatus = (status: string): string => {
      const s = status?.toLowerCase();
      if (s === 'draft') return 'Draft';
      if (s === 'finalized') return 'Finalized';
      if (s === 'sent') return 'Sent';
      if (s === 'approved') return 'Approved';
      return status;
    };

    return (
      <ProtectedRoute>
        <main className="container mx-auto space-y-8 py-8 max-w-7xl">
          {/* Finance Hero Section - Clean, No Icons */}
          <section className="rounded-2xl bg-slate-900 px-8 py-8">
            <p className="text-sm font-semibold uppercase tracking-wider text-emerald-400 mb-2">
              Financial Oversight
            </p>
            <h1 className="text-3xl font-bold text-white">
              Welcome back, {displayName}
            </h1>
            <p className="mt-2 max-w-2xl text-slate-400">
              Monitor quote value, FX exposure, and finalized revenue — all in one place.
            </p>
            <div className="mt-6 flex flex-wrap gap-3">
              <Button size="default" className="bg-white text-slate-900 hover:bg-slate-100" asChild>
                <Link href="/quotes">View All Quotes</Link>
              </Button>
              <Button variant="outline" size="default" className="border-slate-600 text-slate-300 hover:bg-slate-800 hover:text-white" asChild>
                <Link href="/settings">Rate Controls</Link>
              </Button>
            </div>
          </section>

          {/* Finance KPI Widgets - No Icons, Text Only */}
          <section className="grid gap-6 md:grid-cols-3">
            {/* Widget A: Finalized Revenue (PGK) */}
            <Card className="border">
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-muted-foreground">
                  Finalized Revenue (This Month)
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">
                  PGK {finalizedRevenuePGK.toLocaleString('en-US', { maximumFractionDigits: 0 })}
                </div>
                <p className="text-xs text-muted-foreground mt-1">
                  {finalizedThisMonth.length} finalized quotes
                </p>
              </CardContent>
            </Card>

            {/* Widget B: Pipeline Exposure (Draft Quotes in PGK) */}
            <Card className="border">
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-muted-foreground">
                  Pipeline Exposure (Drafts)
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">
                  PGK {pipelinePGK.toLocaleString('en-US', { maximumFractionDigits: 0 })}
                </div>
                <p className="text-xs text-muted-foreground mt-1">
                  {draftQuotes.length} draft quotes in market
                </p>
              </CardContent>
            </Card>

            {/* Widget C: FX Rates - Text List */}
            <Card className="border">
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-muted-foreground">
                  FX Rates
                </CardTitle>
              </CardHeader>
              <CardContent>
                {fxStatus ? (
                  <div className="space-y-1">
                    {fxStatus.rates
                      .filter(r => !r.currency.startsWith('PGK'))
                      .slice(0, 3)
                      .map((rate) => {
                        const base = rate.currency.split('/')[0] || rate.currency;
                        return (
                          <div key={rate.currency} className="flex justify-between text-sm">
                            <span>{base}/PGK</span>
                            <span className="font-mono">{parseFloat(rate.tt_sell).toFixed(4)}</span>
                          </div>
                        );
                      })}
                    <div className="pt-2 border-t mt-2">
                      <p className="text-xs text-muted-foreground">
                        Status: {fxStatus.is_stale ? 'Stale' : 'Current'}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        Source: {fxStatus.source || 'BSP'}
                      </p>
                    </div>
                  </div>
                ) : (
                  <p className="text-sm text-muted-foreground">Loading rates...</p>
                )}
              </CardContent>
            </Card>
          </section>

          {/* Recent Quote Activity Table - New Columns */}
          <Card className="border">
            <CardHeader className="border-b">
              <div className="flex items-center justify-between">
                <div>
                  <CardTitle>Recent Quote Activity</CardTitle>
                  <CardDescription>Latest quotes for audit and review</CardDescription>
                </div>
                <Button variant="outline" size="sm" asChild>
                  <Link href="/quotes">View All</Link>
                </Button>
              </div>
            </CardHeader>
            <CardContent className="p-0">
              {loading ? (
                <div className="flex items-center justify-center py-12 text-muted-foreground">
                  <span className="text-sm">Loading quotes...</span>
                </div>
              ) : error ? (
                <div className="p-4 text-red-600">{error}</div>
              ) : recentQuotes.length === 0 ? (
                <div className="flex flex-col items-center justify-center gap-3 py-12 text-center text-muted-foreground">
                  <p className="text-sm">No quotes available.</p>
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <Table>
                    <TableHeader>
                      <TableRow className="bg-muted/30">
                        <TableHead>Quote #</TableHead>
                        <TableHead>Customer</TableHead>
                        <TableHead>Route</TableHead>
                        <TableHead>Mode</TableHead>
                        <TableHead className="text-right">Total (Inc. GST)</TableHead>
                        <TableHead>Status</TableHead>
                        <TableHead>Action</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {recentQuotes.map((quote) => (
                        <TableRow key={quote.id}>
                          <TableCell className="font-medium">{quote.quote_number}</TableCell>
                          <TableCell>{getCustomerName(quote.customer)}</TableCell>
                          <TableCell className="text-muted-foreground">
                            {formatRoute(quote.origin_location)} → {formatRoute(quote.destination_location)}
                          </TableCell>
                          <TableCell>{formatMode(quote.mode)}</TableCell>
                          <TableCell className="text-right font-medium tabular-nums">
                            PGK {parseFloat(quote.latest_version.totals.total_sell_pgk_incl_gst || quote.latest_version.totals.total_sell_fcy_incl_gst || "0").toLocaleString('en-US', { maximumFractionDigits: 0 })}
                          </TableCell>
                          <TableCell>{formatStatus(quote.status)}</TableCell>
                          <TableCell>
                            <Link href={`/quotes/${quote.id}`} className="text-primary hover:underline text-sm">
                              View Quote
                            </Link>
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              )}
            </CardContent>
          </Card>
        </main>
      </ProtectedRoute>
    );
  }

  // ========== SALES/MANAGER/ADMIN DASHBOARD ==========
  return (
    <ProtectedRoute>
      <main className="container mx-auto space-y-8 py-8 max-w-7xl">
        {/* Sales Hero Section - Premium Gradient */}
        <section className="relative overflow-hidden rounded-3xl bg-gradient-to-br from-slate-900 via-primary/90 to-primary px-8 py-10 shadow-2xl">
          <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,PHN2ZyB3aWR0aD0iNjAiIGhlaWdodD0iNjAiIHZpZXdCb3g9IjAgMCA2MCA2MCIgeG1sbnM9Imh0dHA6Ly93d3cudzMub3JnLzIwMDAvc3ZnIj48ZyBmaWxsPSJub25lIiBmaWxsLXJ1bGU9ImV2ZW5vZGQiPjxnIGZpbGw9IiNmZmZmZmYiIGZpbGwtb3BhY2l0eT0iMC4wMyI+PHBhdGggZD0iTTM2IDM0djItSDI0di0yaDEyek0zNiAyNHYySDI0di0yaDEyeiIvPjwvZz48L2c+PC9zdmc+')] opacity-50" />
          <div className="relative z-10">
            <span className="text-sm font-semibold uppercase tracking-wider text-primary-foreground/70">
              Welcome back, {displayName}
            </span>
            <h1 className="mt-2 text-4xl font-bold text-white tracking-tight">
              Your quoting control center
            </h1>
            <p className="mt-3 max-w-2xl text-lg text-primary-foreground/80">
              Monitor the pipeline, draft new quotes, and keep customers moving — all from one place.
            </p>
            <div className="mt-8 flex flex-wrap gap-4">
              {canEditQuotes && (
                <Button
                  size="lg"
                  className="bg-white text-primary hover:bg-white/90 shadow-lg"
                  asChild
                >
                  <Link href="/quotes/new">
                    <PlusCircle className="mr-2 h-4 w-4" />
                    New Quote
                  </Link>
                </Button>
              )}
              <Button
                variant="secondary"
                size="lg"
                className="bg-white/10 hover:bg-white/20 text-white border-white/20 backdrop-blur-sm"
                asChild
              >
                <Link href="/quotes">
                  View Quotes
                  <ArrowRight className="ml-2 h-4 w-4" />
                </Link>
              </Button>
              <Button
                variant="ghost"
                size="lg"
                className="text-white/80 hover:text-white hover:bg-white/10"
                asChild
              >
                <Link href="/customers">Manage Customers</Link>
              </Button>
            </div>
          </div>
        </section>

        {/* Sales KPI Cards */}
        <section className="grid gap-6 md:grid-cols-3">
          <Card className="relative overflow-hidden border-0 bg-white shadow-lg">
            <div className="absolute top-0 right-0 w-32 h-32 bg-slate-100 rounded-full blur-2xl -translate-y-1/2 translate-x-1/2" />
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2 relative">
              <CardTitle className="text-sm font-medium text-slate-600">Draft Quotes</CardTitle>
              <div className="p-2 bg-slate-100 rounded-lg">
                <FileText className="h-5 w-5 text-slate-500" />
              </div>
            </CardHeader>
            <CardContent className="relative">
              <div className="text-3xl font-bold tracking-tight">{metrics.draftCount}</div>
              <p className="text-sm text-muted-foreground mt-1">Quotes in progress</p>
            </CardContent>
          </Card>

          <Card className="relative overflow-hidden border-0 bg-gradient-to-br from-emerald-50 to-emerald-100/50 shadow-lg">
            <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-200/30 rounded-full blur-2xl -translate-y-1/2 translate-x-1/2" />
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2 relative">
              <CardTitle className="text-sm font-medium text-emerald-700">Finalized Quotes</CardTitle>
              <div className="p-2 bg-emerald-500/10 rounded-lg">
                <CheckCircle2 className="h-5 w-5 text-emerald-600" />
              </div>
            </CardHeader>
            <CardContent className="relative">
              <div className="text-3xl font-bold text-emerald-700 tracking-tight">{metrics.finalizedCount}</div>
              <p className="text-sm text-emerald-600/80 mt-1">Fully rated by engine</p>
            </CardContent>
          </Card>

          <Card className="relative overflow-hidden border-0 bg-gradient-to-br from-primary/5 to-primary/10 shadow-lg">
            <div className="absolute top-0 right-0 w-32 h-32 bg-primary/10 rounded-full blur-2xl -translate-y-1/2 translate-x-1/2" />
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2 relative">
              <CardTitle className="text-sm font-medium text-primary/80">Pipeline Value</CardTitle>
              <div className="p-2 bg-primary/10 rounded-lg">
                <DollarSign className="h-5 w-5 text-primary" />
              </div>
            </CardHeader>
            <CardContent className="relative">
              <div className="text-3xl font-bold text-primary tracking-tight">
                {formatCurrency(metrics.pipelineValue, metrics.currency)}
              </div>
              <p className="text-sm text-primary/60 mt-1">Total value (inc. GST)</p>
            </CardContent>
          </Card>
        </section>

        {/* Recent Activity - Premium Table */}
        <Card className="border-0 shadow-lg overflow-hidden">
          <CardHeader className="bg-slate-50/50 border-b">
            <div className="flex items-center justify-between">
              <div>
                <CardTitle className="text-lg font-semibold">Recent Activity</CardTitle>
                <CardDescription className="mt-1">Latest quotes managed by you and your team</CardDescription>
              </div>
              <Button variant="outline" size="sm" asChild>
                <Link href="/quotes">
                  View All
                  <ArrowRight className="ml-2 h-4 w-4" />
                </Link>
              </Button>
            </div>
          </CardHeader>
          <CardContent className="p-0">{renderRecentQuotes()}</CardContent>
        </Card>
      </main>
    </ProtectedRoute>
  );
}

'use client';

import React, { useEffect, useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { getRateCardV3, RateCard } from '@/lib/api';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import { RateLineDialog } from '@/components/pricing/RateLineDialog';
import { RateLine } from '@/lib/api';
import { ImportRatesDialog } from '@/components/pricing/ImportRatesDialog';
import { Upload, ArrowLeft, Edit, Plus } from 'lucide-react';
import { Badge } from '@/components/ui/badge';

export default function RateCardDetailPage() {
    const params = useParams();
    const router = useRouter();
    const id = params.id as string;
    const [rateCard, setRateCard] = useState<RateCard | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    // Dialog State
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [selectedLine, setSelectedLine] = useState<RateLine | null>(null);
    const [isImportOpen, setIsImportOpen] = useState(false);

    async function fetchCard() {
        try {
            setLoading(true);
            const data = await getRateCardV3(id);
            setRateCard(data);
        } catch (err) {
            setError('Failed to load rate card details.');
            console.error(err);
        } finally {
            setLoading(false);
        }
    }

    useEffect(() => {
        fetchCard();
    }, [id]);

    const handleAddLine = () => {
        setSelectedLine(null);
        setIsDialogOpen(true);
    };

    const handleEditLine = (line: RateLine) => {
        setSelectedLine(line);
        setIsDialogOpen(true);
    };

    const handleSaveLine = () => {
        fetchCard(); // Refresh data
    };

    if (loading && !rateCard) return <div className="p-8">Loading...</div>;
    if (error || !rateCard) return <div className="p-8 text-red-500">{error || 'Rate card not found'}</div>;

    return (
        <div className="container mx-auto py-8 space-y-6">
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <Button variant="ghost" onClick={() => router.back()}>
                        <ArrowLeft className="w-4 h-4 mr-2" />
                        Back
                    </Button>
                    <h1 className="text-3xl font-bold tracking-tight">{rateCard.name}</h1>
                </div>
                <div className="flex gap-2">
                    <Button variant="outline" onClick={() => setIsImportOpen(true)}>
                        <Upload className="w-4 h-4 mr-2" />
                        Import CSV
                    </Button>
                    <Button variant="outline">
                        <Edit className="w-4 h-4 mr-2" />
                        Edit Details
                    </Button>
                    <Button onClick={handleAddLine}>
                        <Plus className="w-4 h-4 mr-2" />
                        Add Line
                    </Button>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <Card className="md:col-span-2">
                    <CardHeader>
                        <CardTitle>Rate Lines</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Component</TableHead>
                                    <TableHead>Method</TableHead>
                                    <TableHead>Min Charge</TableHead>
                                    <TableHead>Rates / Breaks</TableHead>
                                    <TableHead>Actions</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {rateCard.lines?.map((line) => (
                                    <TableRow key={line.id}>
                                        <TableCell className="font-medium">
                                            {line.component_code}
                                            {line.description && (
                                                <div className="text-xs text-muted-foreground">{line.description}</div>
                                            )}
                                        </TableCell>
                                        <TableCell>
                                            <Badge variant="outline">{line.method}</Badge>
                                            {line.unit && <span className="ml-2 text-xs text-muted-foreground">/ {line.unit}</span>}
                                        </TableCell>
                                        <TableCell>
                                            {line.min_charge > 0 ? `${rateCard.currency} ${line.min_charge}` : '-'}
                                        </TableCell>
                                        <TableCell>
                                            {line.method === 'WEIGHT_BREAK' ? (
                                                <div className="space-y-1 text-sm">
                                                    {line.breaks.map((b) => (
                                                        <div key={b.id} className="flex justify-between w-48">
                                                            <span>{b.from_value} - {b.to_value || 'Max'}:</span>
                                                            <span className="font-mono">{b.rate}</span>
                                                        </div>
                                                    ))}
                                                </div>
                                            ) : line.method === 'PERCENT' ? (
                                                <span>{Number(line.percent_value) * 100}% of {line.percent_of_component}</span>
                                            ) : (
                                                // For FLAT or PER_UNIT, check breaks if rate is there
                                                line.breaks.length > 0 ? (
                                                    <span>{line.breaks[0].rate}</span>
                                                ) : '-'
                                            )}
                                        </TableCell>
                                        <TableCell>
                                            <Button variant="ghost" size="sm" onClick={() => handleEditLine(line)}>Edit</Button>
                                        </TableCell>
                                    </TableRow>
                                ))}
                                {!rateCard.lines?.length && (
                                    <TableRow>
                                        <TableCell colSpan={5} className="text-center py-8 text-muted-foreground">
                                            No rate lines found.
                                        </TableCell>
                                    </TableRow>
                                )}
                            </TableBody>
                        </Table>
                    </CardContent>
                </Card>

                <div className="space-y-6">
                    <Card>
                        <CardHeader>
                            <CardTitle>Configuration</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div>
                                <div className="text-sm font-medium text-muted-foreground">Supplier</div>
                                <div>{rateCard.supplier_name}</div>
                            </div>
                            <div>
                                <div className="text-sm font-medium text-muted-foreground">Mode</div>
                                <div>{rateCard.mode}</div>
                            </div>
                            <div>
                                <div className="text-sm font-medium text-muted-foreground">Currency</div>
                                <div>{rateCard.currency}</div>
                            </div>
                            <div>
                                <div className="text-sm font-medium text-muted-foreground">Scope</div>
                                <div>{rateCard.scope}</div>
                            </div>
                            <div>
                                <div className="text-sm font-medium text-muted-foreground">Priority</div>
                                <div>{rateCard.priority}</div>
                            </div>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader>
                            <CardTitle>Validity</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div>
                                <div className="text-sm font-medium text-muted-foreground">Valid From</div>
                                <div>{rateCard.valid_from || 'N/A'}</div>
                            </div>
                            <div>
                                <div className="text-sm font-medium text-muted-foreground">Valid Until</div>
                                <div>{rateCard.valid_until || 'Indefinite'}</div>
                            </div>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardHeader>
                            <CardTitle>Zones</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div>
                                <div className="text-sm font-medium text-muted-foreground">Origin</div>
                                <div>{rateCard.origin_zone_name || rateCard.origin_zone}</div>
                            </div>
                            <div>
                                <div className="text-sm font-medium text-muted-foreground">Destination</div>
                                <div>{rateCard.destination_zone_name || rateCard.destination_zone}</div>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            </div>

            <RateLineDialog
                isOpen={isDialogOpen}
                onClose={() => setIsDialogOpen(false)}
                onSave={handleSaveLine}
                cardId={id}
                initialData={selectedLine}
            />

            <ImportRatesDialog
                isOpen={isImportOpen}
                onClose={() => setIsImportOpen(false)}
                onSuccess={handleSaveLine}
                cardId={id}
            />
        </div>
    );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import { useAuth } from "@/context/auth-context";
import { createQuoteVersion, getQuoteV3, getQuoteCompute, downloadQuotePDF } from "@/lib/api";
import {
  QuoteVersionCreatePayload,
  V3ManualOverride,
  V3QuoteComputeResponse,
  V3QuoteLine,
  QuoteComputeResult,
} from "@/lib/types";
import ManualRateForm from "@/components/ManualRateForm";
import QuoteResultDisplay from "@/components/QuoteResultDisplay";
import QuoteFinancialBreakdown from "@/components/QuoteFinancialBreakdown";
import QuoteSummaryBar from "@/components/QuoteSummaryBar";
import QuoteSettings from "@/components/QuoteSettings";
import RoutingWarning from "@/components/RoutingWarning";
import { BucketSourcingView } from "@/components/pricing/BucketSourcingView";
import { SpotChargeResultDisplay } from "@/components/pricing/SpotChargeResultDisplay";
import { getSpotChargesForQuote } from "@/lib/api";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Loader2, ChevronRight, ArrowLeft, CheckCircle } from "lucide-react";
import { QuoteStatusBadge, QuoteStatusActions, isQuoteEditable } from "@/components/QuoteStatusBadge";

export default function QuoteDetailPage() {
  const { user, token } = useAuth();
  const params = useParams();
  const router = useRouter();
  const id = params.id as string;

  const [quote, setQuote] = useState<V3QuoteComputeResponse | null>(null);
  const [computeResult, setComputeResult] = useState<QuoteComputeResult | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [manualOverrides, setManualOverrides] = useState<V3ManualOverride[]>([]);
  const [recalculateError, setRecalculateError] = useState<string | null>(null);
  const [recalculateLoading, setRecalculateLoading] = useState(false);
  const [recalculateSuccess, setRecalculateSuccess] = useState(false);
  const [hasSpotCharges, setHasSpotCharges] = useState(false);
  const [pdfDownloading, setPdfDownloading] = useState(false);

  useEffect(() => {
    if (id && user) {
      const fetchQuote = async () => {
        setLoading(true);
        setError(null);
        try {
          // Use the new V3 API function
          const data = await getQuoteV3(id);
          setQuote(data);

          // Fetch compute result (ChargeEngine)
          try {
            const computeData = await getQuoteCompute(id);
            setComputeResult(computeData);
          } catch (computeErr) {
            console.error("Failed to fetch compute result:", computeErr);
          }

          // Check if quote has spot charges
          try {
            const spotCharges = await getSpotChargesForQuote(id);
            const totalLines = spotCharges.charges.ORIGIN.length +
              spotCharges.charges.FREIGHT.length +
              spotCharges.charges.DESTINATION.length;
            setHasSpotCharges(totalLines > 0);
          } catch {
            setHasSpotCharges(false);
          }
        } catch (err: unknown) {
          const message =
            err instanceof Error ? err.message : "An unexpected error occurred.";
          setError(message);
        } finally {
          setLoading(false);
        }
      };
      fetchQuote();
    }
  }, [id, user]);

  useEffect(() => {
    if (quote?.latest_version?.payload_json?.overrides) {
      setManualOverrides(quote.latest_version.payload_json.overrides);
    } else {
      setManualOverrides([]);
    }
  }, [quote]);

  const handleManualOverrideSubmit = (override: V3ManualOverride) => {
    setRecalculateSuccess(false);
    setRecalculateError(null);
    setManualOverrides((prev) => {
      const index = prev.findIndex(
        (item) => item.service_component_id === override.service_component_id,
      );
      if (index >= 0) {
        const updated = [...prev];
        updated[index] = override;
        return updated;
      }
      return [...prev, override];
    });
  };

  const handleRecalculate = async () => {
    if (!quote) {
      setRecalculateError("Quote data is unavailable.");
      return;
    }

    // Only require manual overrides if there are actually missing rates
    const hasMissing = quote.latest_version.lines.some(l => l.is_rate_missing);
    if (hasMissing && manualOverrides.length === 0) {
      setRecalculateError("Add manual rates for missing charges before recalculating.");
      return;
    }
    const payload: QuoteVersionCreatePayload = {
      charges: manualOverrides.map((override) => {
        const normalized: V3ManualOverride = {
          service_component_id: override.service_component_id,
          cost_fcy: override.cost_fcy,
          currency: override.currency.toUpperCase(),
          unit: override.unit,
        };
        if (override.min_charge_fcy) {
          normalized.min_charge_fcy = override.min_charge_fcy;
        }
        if (override.valid_until) {
          normalized.valid_until = override.valid_until;
        }
        return normalized;
      }),
    };
    setRecalculateLoading(true);
    setRecalculateError(null);
    setRecalculateSuccess(false);
    try {
      const updatedQuote = await createQuoteVersion(token, quote.id, payload);
      setQuote(updatedQuote);
      setManualOverrides(
        updatedQuote.latest_version?.payload_json?.overrides ??
        payload.charges,
      );
      setRecalculateSuccess(true);

      // Refresh compute result
      const computeData = await getQuoteCompute(quote.id);
      setComputeResult(computeData);

    } catch (err: unknown) {
      const message =
        err instanceof Error ? err.message : "Failed to finalize quote.";
      setRecalculateError(message);
    } finally {
      setRecalculateLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex h-64 items-center justify-center">
        <Loader2 className="mr-2 h-8 w-8 animate-spin" />
        <span>Loading quote...</span>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container mx-auto max-w-6xl p-4">
        <Alert variant="destructive">
          <AlertTitle>Error</AlertTitle>
          <AlertDescription>{error}</AlertDescription>
        </Alert>
      </div>
    );
  }

  if (!quote) {
    return (
      <div className="container mx-auto max-w-6xl p-4">
        <Alert variant="default">
          <AlertTitle>No Quote Found</AlertTitle>
          <AlertDescription>
            The quote you are looking for does not exist.
          </AlertDescription>
        </Alert>
      </div>
    );
  }

  const isIncomplete = quote.status === "INCOMPLETE";

  // For finalized view, use the new two-column layout
  const showFinalizedLayout = !isIncomplete;
  const canDownloadPDF = quote.status === "FINALIZED" || quote.status === "SENT";

  return (
    <div className="container mx-auto max-w-6xl px-4 py-6 space-y-6">
      {/* Breadcrumb Navigation */}
      <nav className="flex items-center gap-2 text-sm text-slate-500">
        <Link href="/quotes" className="hover:text-slate-700 transition-colors">
          Quotes
        </Link>
        <ChevronRight className="w-4 h-4" />
        <span className="text-slate-400">New Quote</span>
        <ChevronRight className="w-4 h-4" />
        <span className="font-medium text-slate-700">Finalize</span>
      </nav>

      {/* Page Header */}
      <div className="flex items-start justify-between">
        <div>
          <div className="flex items-center gap-3 mb-1">
            <h1 className="text-2xl font-bold text-slate-900">
              {quote.quote_number}
            </h1>
            <QuoteStatusBadge status={quote.status} size="default" />
          </div>
          <p className="text-sm text-slate-500">
            Created on {new Date(quote.created_at).toLocaleDateString('en-US', {
              year: 'numeric',
              month: 'short',
              day: 'numeric'
            })} • {quote.shipment_type} Air Freight
          </p>
        </div>
        <div className="flex items-center gap-3">
          <Button
            variant="outline"
            onClick={() => {
              // Check if this is a spot quote derived from an envelope
              const payloadJson = quote.latest_version?.payload_json;
              const speId = payloadJson ? (payloadJson as unknown as { spot_envelope_id?: string }).spot_envelope_id : undefined;
              if (speId) {
                router.push(`/quotes/spot/${speId}`);
              } else {
                router.push(`/quotes/new?edit=${quote.id}`);
              }
            }}
            className="gap-2"
          >
            <ArrowLeft className="w-4 h-4" />
            Back to Edit
          </Button>
          <QuoteStatusActions
            quoteId={quote.id}
            status={quote.status}
            hasMissingRates={quote.latest_version?.totals?.has_missing_rates || false}
            onStatusChange={() => {
              getQuoteV3(id).then((data) => setQuote(data));
            }}
          />
        </div>
      </div>

      {/* Scrollable Content Area with bottom padding for footer */}
      <div className="pb-32 space-y-6">
        {/* Summary Bar - Condensed/Hidden on Scroll if we wanted, but let's keep it simply or remove if redundant */}
        {/* QuoteSummaryBar quote={quote}  <-- REMOVED since we have sticky footer now */}

        {/* Display routing warning if VIA routing is required */}
        {computeResult?.routing && (
          <RoutingWarning routingInfo={computeResult.routing} />
        )}

        {/* Main Content Area */}
        {isIncomplete ? (
          <BucketSourcingView
            quote={quote}
            onFinalizeSuccess={() => {
              // Refresh the quote data and spot charges state after finalization
              getQuoteV3(id).then((data) => {
                setQuote(data);
                setHasSpotCharges(true); // Mark as having spot charges
              });
            }}
          />
        ) : (
          /* Two-Column Layout for Finalized Quotes */
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            {/* Left Column - Financial Breakdown (2/3 width) */}
            <div className="lg:col-span-2 space-y-6">
              {hasSpotCharges ? (
                <SpotChargeResultDisplay quote={quote} />
              ) : computeResult ? (
                <QuoteFinancialBreakdown result={computeResult} />
              ) : (
                <QuoteResultDisplay quote={quote} />
              )}
            </div>

            {/* Right Column - Document Preview & Settings (1/3 width) */}
            <div className="space-y-6">
              <QuoteSettings defaultPaymentTerm={quote.payment_term?.toLowerCase()} />
            </div>
          </div>
        )}
      </div>

      {/* Sticky Footer Action Bar */}
      <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] z-50">
        <div className="container mx-auto max-w-6xl px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-6">
            <div>
              <p className="text-xs text-slate-500 uppercase font-semibold">Total Estimated Cost</p>
              <p className="text-2xl font-bold text-slate-900">
                {quote.latest_version?.totals?.currency || 'PGK'} {parseFloat(quote.latest_version?.totals?.total_sell_fcy_incl_gst || quote.latest_version?.totals?.total_sell_pgk_incl_gst || "0").toLocaleString()}
              </p>
              <p className="text-[10px] text-slate-400">
                Inc. GST
              </p>
            </div>
            {/* Currency Exchange Badge placeholder (future task) */}
            {quote.latest_version?.totals?.currency !== 'PGK' && (
              <div className="hidden md:block px-3 py-1 bg-amber-50 rounded border border-amber-100 text-xs text-amber-700">
                <strong>Note:</strong> Pricing in {quote.latest_version?.totals?.currency}
              </div>
            )}
          </div>

          <div className="flex items-center gap-3">
            {canDownloadPDF && (
              <Button
                variant="outline"
                className="hidden sm:flex"
                disabled={pdfDownloading}
                onClick={async () => {
                  setPdfDownloading(true);
                  try {
                    await downloadQuotePDF(quote.id, quote.quote_number);
                  } catch (err) {
                    console.error("PDF download failed:", err);
                    alert(err instanceof Error ? err.message : "Failed to download PDF");
                  } finally {
                    setPdfDownloading(false);
                  }
                }}
              >
                {pdfDownloading ? (
                  <>
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                    Generating...
                  </>
                ) : (
                  "Download PDF"
                )}
              </Button>
            )}
            {/* Only show finalize button for DRAFT quotes, handled by QuoteStatusActions above */}
            {quote.status === "FINALIZED" || quote.status === "SENT" ? (
              <div className="flex items-center gap-2 text-sm text-slate-500">
                <CheckCircle className="h-4 w-4 text-emerald-600" />
                <span>Quote {quote.status.toLowerCase()}</span>
              </div>
            ) : quote.status === "DRAFT" ? (
              <QuoteStatusActions
                quoteId={quote.id}
                status={quote.status}
                hasMissingRates={quote.latest_version?.totals?.has_missing_rates || false}
                onStatusChange={() => {
                  getQuoteV3(id).then((data) => setQuote(data));
                }}
              />
            ) : null}
          </div>
        </div>
      </div>

    </div>
  );
}

interface ManualSourcingViewProps {
  quote: V3QuoteComputeResponse;
  manualOverrides: V3ManualOverride[];
  recalculateLoading: boolean;
  recalculateError: string | null;
  recalculateSuccess: boolean;
  onManualOverrideSubmit: (override: V3ManualOverride) => void;
  onRecalculate: () => void;
}

type QuoteLineWithOverride = V3QuoteLine & {
  manual_override?: V3ManualOverride;
};

function ManualSourcingView({
  quote,
  manualOverrides,
  recalculateLoading,
  recalculateError,
  recalculateSuccess,
  onManualOverrideSubmit,
  onRecalculate,
}: ManualSourcingViewProps) {
  const lines = quote.latest_version.lines;
  const lineLookup = useMemo(() => {
    return lines.reduce<Record<string, string>>((acc, line) => {
      acc[line.service_component.id] = line.service_component.description;
      return acc;
    }, {});
  }, [lines]);
  const mergedLines = useMemo<QuoteLineWithOverride[]>(() => {
    const overrideMap = manualOverrides.reduce<Map<string, V3ManualOverride>>(
      (acc, override) => acc.set(override.service_component_id, override),
      new Map(),
    );
    return lines.map((line) => {
      const override = overrideMap.get(line.service_component.id);
      if (!override) {
        return line;
      }
      return {
        ...line,
        is_rate_missing: false,
        service_component: {
          ...line.service_component,
          description: `${line.service_component.description} (Manual Rate Added)`,
        },
        manual_override: override,
      };
    });
  }, [lines, manualOverrides]);

  // Check if any lines still have missing rates (not covered by manual overrides)
  const hasMissingRates = useMemo(() => {
    return mergedLines.some((line) => !line.manual_override && line.is_rate_missing);
  }, [mergedLines]);

  return (
    <div className="pb-32"> {/* Added padding for sticky footer in manual mode too */}
      <Card className="overflow-hidden border-destructive/20 shadow-md">
        <CardHeader className="bg-destructive/5 pb-4 border-b border-destructive/10">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-destructive/10 rounded-full">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-destructive"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z" /><line x1="12" x2="12" y1="9" y2="13" /><line x1="12" x2="12.01" y1="17" y2="17" /></svg>
            </div>
            <div>
              <CardTitle className="text-xl text-destructive">
                Action Required: Manual Rates
              </CardTitle>
              <CardDescription>
                Some charges require manual pricing before this quote can be finalized.
              </CardDescription>
            </div>
          </div>
        </CardHeader>
        <CardContent className="p-0">
          <Table>
            <TableHeader className="bg-muted/50">
              <TableRow>
                <TableHead className="pl-6">Charge Line</TableHead>
                <TableHead>Status</TableHead>
                <TableHead className="text-right pr-6">Manual Rate</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {mergedLines.map((line) => {
                const override = line.manual_override;
                const isMissing = !override && line.is_rate_missing;
                const rowClass = isMissing
                  ? "bg-destructive/5 hover:bg-destructive/10"
                  : override
                    ? "bg-amber-50/50 hover:bg-amber-50"
                    : "hover:bg-muted/30";
                return (
                  <TableRow key={line.id} className={rowClass}>
                    <TableCell className="pl-6">
                      <div className="font-semibold text-foreground">
                        {line.service_component.description}
                      </div>
                      <p className="text-xs text-muted-foreground uppercase tracking-wider mt-0.5">
                        {line.service_component.category}
                      </p>
                    </TableCell>
                    <TableCell>
                      {override ? (
                        <Badge variant="outline" className="bg-amber-100 text-amber-700 border-amber-200">
                          Manual Rate
                        </Badge>
                      ) : isMissing ? (
                        <Badge variant="destructive">
                          Required
                        </Badge>
                      ) : (
                        <Badge variant="secondary" className="bg-emerald-100 text-emerald-700 hover:bg-emerald-100">
                          Ready
                        </Badge>
                      )}
                    </TableCell>
                    <TableCell className="text-right pr-6">
                      {override ? (
                        <div className="flex items-center justify-end gap-3">
                          <div className="text-right">
                            <div className="font-mono font-semibold">
                              {override.cost_fcy} {override.currency}
                            </div>
                            <p className="text-xs text-muted-foreground">
                              {override.unit}
                              {override.min_charge_fcy
                                ? ` • Min ${override.min_charge_fcy}`
                                : ""}
                            </p>
                          </div>
                          <ManualRateForm
                            service_component_id={line.service_component.id}
                            service_component_desc={
                              line.service_component.description
                            }
                            onSubmit={onManualOverrideSubmit}
                            triggerLabel="Edit"
                          />
                        </div>
                      ) : isMissing ? (
                        <ManualRateForm
                          service_component_id={line.service_component.id}
                          service_component_desc={
                            line.service_component.description
                          }
                          onSubmit={onManualOverrideSubmit}
                          triggerLabel="Add Rate"
                        />
                      ) : (
                        <span className="text-sm text-muted-foreground">—</span>
                      )}
                    </TableCell>
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        </CardContent>
        <CardContent className="p-6 bg-muted/10 border-t">
          <div className="flex items-center justify-between">
            <div>
              <h3 className="text-sm font-semibold uppercase tracking-wide text-muted-foreground mb-2">Manual Rates Summary</h3>
              {manualOverrides.length === 0 ? (
                <p className="text-sm text-muted-foreground italic">
                  No manual rates captured yet.
                </p>
              ) : (
                <div className="flex flex-wrap gap-2">
                  {manualOverrides.map((override) => (
                    <Badge key={override.service_component_id} variant="outline" className="bg-background">
                      {lineLookup[override.service_component_id] || override.service_component_id}: {override.cost_fcy} {override.currency}
                    </Badge>
                  ))}
                </div>
              )}
            </div>
            <div className="flex flex-col items-end gap-2">
              {recalculateError && (
                <p className="text-sm text-destructive font-medium">{recalculateError}</p>
              )}
              {recalculateSuccess && (
                <p className="text-sm text-emerald-600 font-medium">Quote updated successfully!</p>
              )}
              <Button
                size="lg"
                disabled={recalculateLoading || (hasMissingRates && manualOverrides.length === 0)}
                onClick={onRecalculate}
                className="shadow-md"
              >
                {recalculateLoading && (
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                )}
                Recalculate & Finalize
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useState, useEffect, useMemo } from "react";
import { zodResolver } from "@hookform/resolvers/zod";
import { useForm, useFieldArray, useWatch, type Resolver, type FieldErrors } from "react-hook-form";
import { Trash2, Loader2 } from "lucide-react";
import type {
  Contact,
  CompanySearchResult,
  LocationSearchResult,
  V3QuoteComputeRequest,
} from "@/lib/types";
import { getContactsForCompany, computeQuoteV3, validateSpotScope, evaluateSpotTrigger, createSpotEnvelope } from "@/lib/api";
import { useSpotMode } from "@/hooks/use-spot-mode";
import { SpotModeBanner, OutOfScopeBanner } from "@/components/spot";
import type { SPECommodity, TriggerResult } from "@/lib/spot-types";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import {
  quoteFormSchemaV3,
  type QuoteFormSchemaV3,
  V3_MODES,
  V3_INCOTERMS,
  V3_PAYMENT_TERMS,
  V3_SERVICE_SCOPES,
  V3_LOCATION_TYPES,
  V3_CARGO_TYPES,
  getValidIncoterms,
  getDefaultIncoterm,
} from "@/lib/schemas/quoteSchema";
import { Button } from "@/components/ui/button";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import LocationSearchCombobox from "@/components/LocationSearchCombobox";
import CompanySearchCombobox from "@/components/CompanySearchCombobox";
import { useAuth } from "@/context/auth-context";
import { useRouter } from "next/navigation";
import { MissingRatesModal } from "@/components/pricing/MissingRatesModal";

const buildQuoteComputePayload = (
  data: QuoteFormSchemaV3,
  spotRates?: {
    carrierSpotRatePgk: string;
    agentDestChargesFcy: string;
    agentCurrency: string;
    isAllIn?: boolean;
  },
  existingQuoteId?: string | null
): V3QuoteComputeRequest => {
  const payload: V3QuoteComputeRequest = {
    quote_id: existingQuoteId || undefined,
    customer_id: data.customer_id,
    contact_id: data.contact_id,
    mode: data.mode,
    incoterm: data.incoterm,
    payment_term: data.payment_term,
    service_scope: data.service_scope,
    origin_location_id: data.origin_location_id,
    destination_location_id: data.destination_location_id,
    dimensions: data.dimensions.map((dimension) => ({
      pieces: dimension.pieces,
      length_cm: dimension.length_cm,
      width_cm: dimension.width_cm,
      height_cm: dimension.height_cm,
      gross_weight_kg: dimension.gross_weight_kg,
    })),
    overrides: data.overrides?.map((override) => ({
      service_component_id: override.service_component_id,
      cost_fcy: override.cost_fcy,
      currency: override.currency,
      unit: override.unit,
      min_charge_fcy: override.min_charge_fcy,
    })),
    is_dangerous_goods: data.cargo_type === V3_CARGO_TYPES.DANGEROUS_GOODS,
    output_currency: data.output_currency || undefined,
  };

  if (spotRates) {
    const spots: Record<string, unknown> = {};
    if (spotRates.carrierSpotRatePgk) {
      spots['FRT_AIR_EXP'] = {
        amount: spotRates.carrierSpotRatePgk,
        currency: 'PGK',
        is_all_in: spotRates.isAllIn
      };
    }
    if (spotRates.agentDestChargesFcy) {
      spots['DST_CHARGES'] = {
        amount: spotRates.agentDestChargesFcy,
        currency: spotRates.agentCurrency || 'USD'
      };
    }
    if (Object.keys(spots).length > 0) {
      payload.spot_rates = spots;
    }
  }

  return payload;
};

export default function NewQuotePage() {
  const { user } = useAuth();
  const router = useRouter();
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | null>(null);
  const [selectedCustomer, setSelectedCustomer] = useState<CompanySearchResult | null>(null);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [isLoadingContacts, setIsLoadingContacts] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);
  const [originLocation, setOriginLocation] = useState<LocationSearchResult | null>(null);
  const [destinationLocation, setDestinationLocation] = useState<LocationSearchResult | null>(null);

  // Spot Rate State
  const [spotRates, setSpotRates] = useState({
    carrierSpotRatePgk: "",
    agentDestChargesFcy: "",
    agentCurrency: "USD",
    isAllIn: false
  });
  const [missingRates, setMissingRates] = useState({
    carrier: false,
    agent: false
  });
  const [showMissingRatesModal, setShowMissingRatesModal] = useState(false);
  const [pendingQuoteId, setPendingQuoteId] = useState<string | null>(null);
  const [pendingFormData, setPendingFormData] = useState<QuoteFormSchemaV3 | null>(null);

  // SPOT Mode State
  const { state: spotState, actions: spotActions } = useSpotMode();

  const form = useForm<QuoteFormSchemaV3>({
    resolver: zodResolver(quoteFormSchemaV3) as Resolver<QuoteFormSchemaV3>,
    mode: "onChange",
    reValidateMode: "onChange",
    defaultValues: {
      customer_id: "",
      contact_id: "",
      mode: "AIR",
      incoterm: "EXW",
      payment_term: "PREPAID",
      service_scope: V3_SERVICE_SCOPES.A2A,
      origin_airport: "",
      destination_airport: "",
      origin_location_type: V3_LOCATION_TYPES.AIRPORT,
      origin_location_id: "",
      destination_location_type: V3_LOCATION_TYPES.AIRPORT,
      destination_location_id: "",
      cargo_type: V3_CARGO_TYPES.GENERAL,
      dimensions: [{
        pieces: 1,
        length_cm: "",
        width_cm: "",
        height_cm: "",
        gross_weight_kg: "",
        package_type: "Box",
      }],
    },
  });
  const { isValid, isDirty } = form.formState;
  const canCalculateQuote = isDirty && isValid;

  const { fields, append, remove } = useFieldArray({
    control: form.control,
    name: "dimensions",
  });

  // Live Cargo Metrics Calculation - useWatch for proper reactivity
  const watchedDimensions = useWatch({
    control: form.control,
    name: "dimensions",
  });

  const cargoMetrics = useMemo(() => {
    if (!watchedDimensions || watchedDimensions.length === 0) {
      return { pieces: 0, actualWeight: 0, volumetricWeight: 0, chargeableWeight: 0 };
    }

    let totalPieces = 0;
    let totalActual = 0;
    let totalVolumetric = 0;

    for (const dim of watchedDimensions) {
      const pcs = parseInt(String(dim.pieces), 10) || 0;
      const l = parseFloat(String(dim.length_cm)) || 0;
      const w = parseFloat(String(dim.width_cm)) || 0;
      const h = parseFloat(String(dim.height_cm)) || 0;
      const kg = parseFloat(String(dim.gross_weight_kg)) || 0;

      totalPieces += pcs;
      totalActual += kg;
      totalVolumetric += (l * w * h / 6000) * pcs;
    }

    // Chargeable weight is max of actual vs volumetric, rounded UP to next kg
    const chargeableRaw = Math.max(totalActual, totalVolumetric);
    const chargeableRounded = chargeableRaw > 0 ? Math.ceil(chargeableRaw) : 0;

    return {
      pieces: totalPieces,
      actualWeight: Math.round(totalActual * 10) / 10,
      volumetricWeight: Math.round(totalVolumetric * 10) / 10,
      chargeableWeight: chargeableRounded,
    };
  }, [watchedDimensions]);

  const originLocationId = form.watch("origin_location_id");
  const destinationLocationId = form.watch("destination_location_id");

  useEffect(() => {
    if (!originLocationId) {
      setOriginLocation(null);
    }
  }, [originLocationId]);

  useEffect(() => {
    if (!destinationLocationId) {
      setDestinationLocation(null);
    }
  }, [destinationLocationId]);

  const setLocationFields = (
    kind: "origin" | "destination",
    location: LocationSearchResult | null,
    onLocationIdChange: (value: string) => void,
  ) => {
    const locationId = location?.id ?? "";
    const airportCode = (location?.code ?? "").toUpperCase();

    onLocationIdChange(locationId);

    if (kind === "origin") {
      form.setValue("origin_location_type", V3_LOCATION_TYPES.AIRPORT, {
        shouldDirty: true,
        shouldValidate: true,
      });
      form.setValue("origin_airport", airportCode, {
        shouldDirty: true,
        shouldValidate: true,
      });
    } else {
      form.setValue("destination_location_type", V3_LOCATION_TYPES.AIRPORT, {
        shouldDirty: true,
        shouldValidate: true,
      });
      form.setValue("destination_airport", airportCode, {
        shouldDirty: true,
        shouldValidate: true,
      });
    }
  };

  // Determine if this is an Import (destination is PNG)
  const isImport = destinationLocation?.country_code === 'PG';

  // Watch form fields for incoterm filtering
  const serviceScope = form.watch('service_scope');
  const paymentTerm = form.watch('payment_term');
  const currentIncoterm = form.watch('incoterm');

  // Get valid incoterms based on direction, scope, and payment term
  const validIncoterms = useMemo(() => {
    return getValidIncoterms(isImport, serviceScope, paymentTerm);
  }, [isImport, serviceScope, paymentTerm]);

  // Auto-select correct incoterm when scope, direction, or payment term changes
  useEffect(() => {
    if (!validIncoterms.includes(currentIncoterm)) {
      const defaultIncoterm = getDefaultIncoterm(isImport, serviceScope, paymentTerm);
      form.setValue('incoterm', defaultIncoterm as keyof typeof V3_INCOTERMS, {
        shouldValidate: true,
      });
    }
  }, [validIncoterms, currentIncoterm, isImport, serviceScope, paymentTerm, form]);

  useEffect(() => {
    const fetchContacts = async (customerId: string) => {
      if (!user || !customerId) return;
      setIsLoadingContacts(true);
      setContacts([]);
      try {
        const fetchedContacts = await getContactsForCompany(customerId);
        setContacts(fetchedContacts);
      } catch (error: unknown) {
        console.error("Error fetching contacts:", error);
        setApiError("Failed to fetch contacts.");
      } finally {
        setIsLoadingContacts(false);
      }
    };

    if (selectedCustomerId) {
      fetchContacts(selectedCustomerId);
    }
  }, [selectedCustomerId, user]);

  // Reset any pending quote linkage when the customer changes
  useEffect(() => {
    setPendingQuoteId(null);
  }, [selectedCustomerId]);

  function addPieceLine() {
    append({
      pieces: 1,
      length_cm: "0",
      width_cm: "0",
      height_cm: "0",
      gross_weight_kg: "0",
      package_type: "Box",
    });
  }

  // Handler for modal spot rate submission
  const handleMissingRatesSubmit = async (newSpotRates: {
    carrierSpotRatePgk: string;
    agentDestChargesFcy: string;
    agentCurrency: string;
    isAllIn: boolean;
  }) => {
    if (!pendingFormData || !user) return;

    setIsSubmitting(true);
    setSpotRates(newSpotRates);
    setShowMissingRatesModal(false);
    setApiError(null);

    try {
      const payload = buildQuoteComputePayload(pendingFormData, newSpotRates, pendingQuoteId);
      console.log('Recalculating with spot rates:', JSON.stringify(payload.spot_rates, null, 2));

      const response = await computeQuoteV3(payload);
      console.log('Recalculate response:', response.id, 'has_missing_rates:', response.latest_version.totals.has_missing_rates);

      // Check if still missing rates
      if (response.latest_version.totals.has_missing_rates) {
        // Update pending quote ID in case it changed
        setPendingQuoteId(response.id);

        // Recheck which rates are still missing
        const lines = response.latest_version.lines;
        const stillMissingCarrier = lines.some(l => l.service_component.code === 'FRT_AIR_EXP' && l.is_rate_missing);
        const destComponents = ['DST-DELIV-STD', 'DST-CLEAR-CUS', 'DST-HANDL-STD', 'DST-DOC-IMP', 'DST_CHARGES'];
        const stillMissingAgent = lines.some(l => destComponents.includes(l.service_component.code) && l.is_rate_missing);

        setMissingRates({ carrier: stillMissingCarrier, agent: stillMissingAgent });
        setShowMissingRatesModal(true);
        setApiError("Some rates are still missing. Please verify your entries.");
        setIsSubmitting(false);
        return;
      }

      // Success! Clean up and redirect
      setPendingQuoteId(null);
      setPendingFormData(null);
      setMissingRates({ carrier: false, agent: false });
      router.push(`/quotes/${response.id}`);
    } catch (error: unknown) {
      console.error("API Error during recalculation:", error);
      const message = error instanceof Error ? error.message : "An unexpected error occurred.";
      setApiError(message);
      // Reopen modal so user can try again
      setShowMissingRatesModal(true);
    } finally {
      setIsSubmitting(false);
    }
  };

  // Map frontend cargo type to SPE commodity code
  const mapCargoToSPECommodity = (cargoType: string): SPECommodity => {
    switch (cargoType) {
      case 'Dangerous Goods': return 'DG';
      case 'Perishable / Cold Chain': return 'PER';
      case 'Live Animals': return 'AVI';
      case 'Valuable / High-Value': return 'HVC';
      case 'Oversized / OOG': return 'OOG';
      case 'General Cargo':
      default: return 'GCR';
    }
  };

  async function onSubmit(data: QuoteFormSchemaV3) {
    setIsSubmitting(true);
    setApiError(null);
    setMissingRates({ carrier: false, agent: false });

    if (!user) {
      setApiError("Authentication token not available. Please log in.");
      setIsSubmitting(false);
      return;
    }

    // Get country codes from locations
    const originCountry = originLocation?.country_code || '';
    const destCountry = destinationLocation?.country_code || '';

    // SPOT Mode Step 1: Validate scope (PNG only)
    try {
      const scopeResult = await validateSpotScope({
        origin_country: originCountry,
        destination_country: destCountry,
      });

      if (!scopeResult.is_valid) {
        // Out of scope - hard block
        setApiError(scopeResult.error || "Shipment out of scope - only PNG routes supported");
        setIsSubmitting(false);
        return;
      }
    } catch (error) {
      console.error("Scope validation error:", error);
      // If scope validation fails, continue with normal flow
      // (backend will catch any scope issues)
    }

    // SPOT Mode Step 2: Evaluate trigger
    try {
      const commodity = mapCargoToSPECommodity(data.cargo_type);
      const triggerResult = await evaluateSpotTrigger({
        origin_country: originCountry,
        destination_country: destCountry,
        commodity,
        origin_airport: data.origin_airport,
        destination_airport: data.destination_airport,
        has_valid_buy_rate: true, // Will be determined by pricing attempt
        service_scope: data.service_scope,
      });

      if (triggerResult.is_spot_required && triggerResult.trigger) {
        // SPOT mode required - create SPE immediately and redirect to intake
        try {
          const spe = await createSpotEnvelope({
            shipment_context: {
              origin_country: originCountry,
              destination_country: destCountry,
              origin_code: data.origin_airport || '',
              destination_code: data.destination_airport || '',
              commodity: commodity as SPECommodity,
              total_weight_kg: cargoMetrics.chargeableWeight,
              pieces: cargoMetrics.pieces,
              service_scope: (data.service_scope || 'P2P').toLowerCase(),
            },
            charges: [], // Empty for now, will be filled via AI intake
            trigger_code: triggerResult.trigger.code,
            trigger_text: triggerResult.trigger.text,
            conditions: {
              rate_validity_hours: 72,
            }
          });

          if (spe) {
            const shipmentType =
              originCountry === 'PG' && destCountry === 'PG'
                ? 'DOMESTIC'
                : originCountry === 'PG'
                  ? 'EXPORT'
                  : 'IMPORT';
            const params = new URLSearchParams({
              origin_country: originCountry,
              dest_country: destCountry,
              origin_code: data.origin_airport || '',
              dest_code: data.destination_airport || '',
              commodity,
              weight: String(cargoMetrics.chargeableWeight),
              pieces: String(cargoMetrics.pieces),
              trigger_code: triggerResult.trigger.code,
              trigger_text: triggerResult.trigger.text,
              service_scope: data.service_scope,
              payment_term: data.payment_term,
              output_currency: data.output_currency || 'PGK',
              shipment_type: shipmentType,
            });

            if (triggerResult.trigger.missing_components && triggerResult.trigger.missing_components.length > 0) {
              params.append('missing_components', triggerResult.trigger.missing_components.join(','));
            }

            router.push(`/quotes/spot/${spe.id}?${params.toString()}`);
          }
        } catch (speError) {
          console.error("Failed to create SPE:", speError);
          // If SPE creation fails, provide feedback or fallback
          setApiError("Failed to initialize SPOT pricing session. Please try again.");
        }
        return;
      }
    } catch (error) {
      console.error("Trigger evaluation error:", error);
      // If trigger eval fails, continue with normal flow
    }

    // Normal pricing flow
    try {
      // Always include spot rates if they are populated
      const payload = buildQuoteComputePayload(data, spotRates, pendingQuoteId);
      const response = await computeQuoteV3(payload);
      console.log('Quote compute response:', response);

      // Check for missing rates (with null-safe access)
      const hasMissingRates = response.latest_version?.totals?.has_missing_rates ?? false;
      if (hasMissingRates) {
        const lines = response.latest_version?.lines ?? [];
        let missingCarrier = false;
        let missingAgent = false;

        // Check for missing carrier rates (FRT_AIR_EXP)
        if (lines.some(l => l.service_component.code === 'FRT_AIR_EXP' && l.is_rate_missing)) {
          missingCarrier = true;
        }

        // Check for missing agent rates (Destination Charges)
        const destComponents = ['DST-DELIV-STD', 'DST-CLEAR-CUS', 'DST-HANDL-STD', 'DST-DOC-IMP', 'DST_CHARGES'];
        if (lines.some(l => destComponents.includes(l.service_component.code) && l.is_rate_missing)) {
          missingAgent = true;
        }

        if (missingCarrier || missingAgent) {
          setMissingRates({ carrier: missingCarrier, agent: missingAgent });
          setPendingQuoteId(response.id);
          setPendingFormData(data);
          setShowMissingRatesModal(true);
          setIsSubmitting(false);
          return;
        }
      }

      console.log('Redirecting to quote:', response.id);
      setPendingQuoteId(null);
      router.push(`/quotes/${response.id}`);
    } catch (error: unknown) {
      console.error("API Error:", error);
      const message =
        error instanceof Error && error.message
          ? error.message
          : "An unexpected error occurred.";
      setApiError(message);
    } finally {
      setIsSubmitting(false);
    }
  }

  const onInvalid = (errors: FieldErrors<QuoteFormSchemaV3>) => {
    console.error("Form validation errors:", JSON.stringify(errors, null, 2));
    console.log("Current form values:", form.getValues());

    const firstErrorKey = Object.keys(errors)[0];

    // Helper to find the first message in a nested error object
    const getErrorMessage = (error: unknown): string | null => {
      if (!error) return null;
      if (typeof error === 'string') return error;

      if (typeof error === 'object' && error !== null) {
        // Check for 'message' property safely
        const hasMessage = 'message' in error && typeof (error as Record<string, unknown>).message === 'string';
        if (hasMessage) {
          return (error as Record<string, unknown>).message as string;
        }

        // Check for 'root' property safely
        const hasRoot = 'root' in error;
        if (hasRoot) {
          return getErrorMessage((error as Record<string, unknown>).root);
        }

        // If it's an array or object, try to find the first child with a message
        for (const key in error) {
          const childMsg = getErrorMessage((error as Record<string, unknown>)[key]);
          if (childMsg) return childMsg;
        }
      }
      return null;
    };

    const errorMessage = getErrorMessage(errors) || "Please check all required fields.";

    setApiError(`Validation Error: ${errorMessage}`);

    // Attempt to scroll to the error
    if (firstErrorKey) {
      const errorElement = document.querySelector(`[name="${firstErrorKey}"]`);
      if (errorElement) {
        errorElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
        (errorElement as HTMLElement).focus();
      } else {
        // Fallback for fields that might not map directly to a name attribute (e.g. dimensions root)
        window.scrollTo({ top: 0, behavior: 'smooth' });
      }
    } else {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  return (
    <div className="container mx-auto max-w-5xl p-4 pb-32">
      <Form {...form}>
        <form onSubmit={form.handleSubmit(onSubmit, onInvalid)} className="space-y-6">
          <div className="flex items-center justify-between">
            <h1 className="text-3xl font-bold">New Quote</h1>
          </div>

          {apiError && !missingRates.carrier && !missingRates.agent && (
            <Alert variant="destructive">
              <AlertTitle>Error</AlertTitle>
              <AlertDescription>{apiError}</AlertDescription>
            </Alert>
          )}

          {/* No SPOT banner - auto-redirect is handled in onSubmit */}

          {/* 1. Customer */}
          <Card>
            <CardHeader>
              <CardTitle>Customer</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <FormField
                control={form.control}
                name="customer_id"
                render={({ field }) => (
                  <FormItem className="flex flex-col">
                    <FormLabel>Customer</FormLabel>
                    <CompanySearchCombobox
                      value={selectedCustomer}
                      onSelect={(company) => {
                        setSelectedCustomer(company);
                        const companyId = company?.id ?? null;
                        field.onChange(companyId ?? "");
                        setSelectedCustomerId(companyId);
                        setContacts([]);
                        form.resetField("contact_id");
                      }}
                    />
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="contact_id"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Contact</FormLabel>
                    <Select
                      onValueChange={field.onChange}
                      value={field.value || ""}
                      disabled={!selectedCustomerId || isLoadingContacts}
                    >
                      <FormControl>
                        <SelectTrigger>
                          <SelectValue
                            placeholder={
                              isLoadingContacts
                                ? "Loading contacts..."
                                : !selectedCustomerId
                                  ? "Select customer first"
                                  : "Select a contact"
                            }
                          />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent>
                        {isLoadingContacts ? (
                          <SelectItem value="loading" disabled>
                            Loading...
                          </SelectItem>
                        ) : contacts.length > 0 ? (
                          contacts.map((contact) => (
                            <SelectItem key={contact.id} value={contact.id}>
                              {contact.first_name} {contact.last_name} ({contact.email})
                            </SelectItem>
                          ))
                        ) : (
                          <SelectItem value="no-contacts" disabled>
                            {selectedCustomerId
                              ? "No contacts found"
                              : "Select customer first"}
                          </SelectItem>
                        )}
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </CardContent>
          </Card>

          {/* 2. Routing */}
          <Card>
            <CardHeader>
              <CardTitle>Routing</CardTitle>
              <CardDescription>
                Shipment type (import/export/domestic) is detected automatically.
              </CardDescription>
            </CardHeader>
            <CardContent className="grid grid-cols-1 gap-6 md:grid-cols-2">
              <FormField
                control={form.control}
                name="origin_location_id"
                render={({ field }) => (
                  <FormItem className="flex flex-col">
                    <FormLabel>Origin Location</FormLabel>
                    <LocationSearchCombobox
                      value={field.value || null}
                      selectedLabel={originLocation?.display_name ?? null}
                      onSelect={(selection) => {
                        setOriginLocation(selection);
                        setLocationFields("origin", selection, field.onChange);
                      }}
                    />
                    <FormDescription>Select any supported location (airport, port, city, or address).</FormDescription>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="destination_location_id"
                render={({ field }) => (
                  <FormItem className="flex flex-col">
                    <FormLabel>Destination Location</FormLabel>
                    <LocationSearchCombobox
                      value={field.value || null}
                      selectedLabel={destinationLocation?.display_name ?? null}
                      onSelect={(selection) => {
                        setDestinationLocation(selection);
                        setLocationFields("destination", selection, field.onChange);
                      }}
                    />
                    <FormDescription>Select any supported location (airport, port, city, or address).</FormDescription>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </CardContent>
          </Card>

          {/* 3. Shipment & Terms */}
          <Card>
            <CardHeader>
              <CardTitle>Shipment & Terms</CardTitle>
            </CardHeader>
            <CardContent className="grid grid-cols-1 gap-4 md:grid-cols-3">
              <FormField
                control={form.control}
                name="mode"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Mode</FormLabel>
                    <Select onValueChange={field.onChange} value={field.value}>
                      <FormControl>
                        <SelectTrigger>
                          <SelectValue placeholder="Select mode" />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent>
                        {Object.values(V3_MODES).map((mode) => (
                          <SelectItem key={mode} value={mode}>
                            {mode}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="incoterm"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Incoterm</FormLabel>
                    <Select onValueChange={field.onChange} value={field.value}>
                      <FormControl>
                        <SelectTrigger>
                          <SelectValue placeholder="Select incoterm" />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent>
                        {validIncoterms.map((incoterm) => (
                          <SelectItem key={incoterm} value={incoterm}>
                            {incoterm}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    {validIncoterms.length === 1 && isImport && serviceScope === 'A2D' && (
                      <FormDescription className="text-amber-600">
                        Import A2D quotes require DAP (Delivered at Place)
                      </FormDescription>
                    )}
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="payment_term"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Payment Term</FormLabel>
                    <Select onValueChange={field.onChange} value={field.value}>
                      <FormControl>
                        <SelectTrigger>
                          <SelectValue placeholder="Select payment term" />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent>
                        {Object.values(V3_PAYMENT_TERMS).map((term) => (
                          <SelectItem key={term} value={term}>
                            {term}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="service_scope"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Service Scope</FormLabel>
                    <Select onValueChange={field.onChange} value={field.value}>
                      <FormControl>
                        <SelectTrigger>
                          <SelectValue placeholder="Select scope" />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent>
                        {Object.values(V3_SERVICE_SCOPES).map((scope) => (
                          <SelectItem key={scope} value={scope}>
                            {scope}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    <FormDescription>Door/Airport selection for pricing logic.</FormDescription>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Cargo Category (Moved from Other Details) */}
              <FormField
                control={form.control}
                name="cargo_type"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Cargo Category</FormLabel>
                    <Select onValueChange={field.onChange} value={field.value}>
                      <FormControl>
                        <SelectTrigger>
                          <SelectValue placeholder="Select category" />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent>
                        {Object.values(V3_CARGO_TYPES).map((type) => (
                          <SelectItem key={type} value={type}>
                            {type}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </CardContent>
          </Card>

          {/* 4. Cargo Dimensions */}
          <Card>
            <CardHeader>
              <CardTitle>Cargo Dimensions</CardTitle>
              <CardDescription>
                Provide at least one piece line with dimensions and weight.
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              {fields.map((fieldItem, index) => (
                <Card key={fieldItem.id}>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0">
                    <CardTitle className="text-base font-semibold">
                      Piece {index + 1}
                    </CardTitle>
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      onClick={() => remove(index)}
                      aria-label={`Remove piece ${index + 1}`}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </CardHeader>
                  <CardContent>
                    <div className="grid grid-cols-1 gap-3 md:grid-cols-6">
                      <FormField
                        control={form.control}
                        name={`dimensions.${index}.package_type`}
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Type</FormLabel>
                            <Select onValueChange={field.onChange} value={field.value}>
                              <FormControl>
                                <SelectTrigger>
                                  <SelectValue placeholder="Type" />
                                </SelectTrigger>
                              </FormControl>
                              <SelectContent>
                                <SelectItem value="Box">Box</SelectItem>
                                <SelectItem value="Pallet">Pallet</SelectItem>
                                <SelectItem value="Crate">Crate</SelectItem>
                                <SelectItem value="Skid">Skid</SelectItem>
                                <SelectItem value="Drum">Drum</SelectItem>
                                <SelectItem value="Loose">Loose</SelectItem>
                              </SelectContent>
                            </Select>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={form.control}
                        name={`dimensions.${index}.pieces`}
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Pieces</FormLabel>
                            <FormControl>
                              <Input type="number" min={1} {...field} />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={form.control}
                        name={`dimensions.${index}.length_cm`}
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Length (cm)</FormLabel>
                            <FormControl>
                              <Input type="number" step="0.01" min="0" {...field} />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={form.control}
                        name={`dimensions.${index}.width_cm`}
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Width (cm)</FormLabel>
                            <FormControl>
                              <Input type="number" step="0.01" min="0" {...field} />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={form.control}
                        name={`dimensions.${index}.height_cm`}
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Height (cm)</FormLabel>
                            <FormControl>
                              <Input type="number" step="0.01" min="0" {...field} />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={form.control}
                        name={`dimensions.${index}.gross_weight_kg`}
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Weight (kg)</FormLabel>
                            <FormControl>
                              <Input type="number" step="0.01" min="0" {...field} />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                    </div>
                  </CardContent>
                </Card>
              ))}
              <Button
                type="button"
                variant="secondary"
                className="w-full"
                onClick={addPieceLine}
              >
                Add Piece Line
              </Button>
              {form.formState.errors.dimensions?.root?.message && (
                <p className="text-sm font-medium text-destructive">
                  {form.formState.errors.dimensions.root.message}
                </p>
              )}
            </CardContent>
          </Card>

          {/* Cargo Summary Display */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 p-4 bg-gradient-to-r from-muted/30 to-muted/50 rounded-lg border">
            <div className="text-center">
              <div className="text-xs font-medium text-muted-foreground uppercase tracking-wide">Pieces</div>
              <div className="text-xl font-bold text-foreground tabular-nums">{cargoMetrics.pieces}</div>
            </div>
            <div className="text-center">
              <div className="text-xs font-medium text-muted-foreground uppercase tracking-wide">Actual</div>
              <div className="text-xl font-bold text-foreground tabular-nums">{cargoMetrics.actualWeight} kg</div>
            </div>
            <div className="text-center">
              <div className="text-xs font-medium text-muted-foreground uppercase tracking-wide">Volumetric</div>
              <div className="text-xl font-bold text-foreground tabular-nums">{cargoMetrics.volumetricWeight} kg</div>
            </div>
            <div className="text-center">
              <div className="text-xs font-medium text-muted-foreground uppercase tracking-wide">Chargeable</div>
              <div className="text-2xl font-bold text-primary tabular-nums">{cargoMetrics.chargeableWeight} kg</div>
            </div>
          </div>

          {/* Sticky Footer */}
          <div className="fixed bottom-0 left-0 right-0 border-t bg-background p-4 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)] md:pl-64 z-50">
            <div className="container mx-auto flex max-w-5xl items-center justify-between">
              <div className="text-sm text-muted-foreground hidden md:block">
                {canCalculateQuote ? "Ready to calculate." : "Complete all required fields to calculate."}
              </div>
              <Button
                type="submit"
                size="lg"
                disabled={isSubmitting}
                className="w-full md:w-auto min-w-[200px] h-12 text-base font-semibold shadow-lg bg-gradient-to-r from-primary to-primary/80 hover:from-primary/90 hover:to-primary/70 transition-all"
              >
                {isSubmitting && <Loader2 className="mr-2 h-5 w-5 animate-spin" />}
                Calculate Quote
              </Button>
            </div>
          </div>

        </form>
      </Form>

      {/* Missing Rates Modal - Email template only */}
      <MissingRatesModal
        isOpen={showMissingRatesModal}
        onClose={() => {
          setShowMissingRatesModal(false);
          // Route to quote detail page if quote was already saved
          if (pendingQuoteId) {
            router.push(`/quotes/${pendingQuoteId}`);
          }
        }}
        onSubmit={() => {
          // Track that email was copied, then navigate to quote
          console.log('Email template copied for partner quote');
          setShowMissingRatesModal(false);
          if (pendingQuoteId) {
            router.push(`/quotes/${pendingQuoteId}`);
          }
        }}
        missingRates={missingRates}
        quoteId={pendingQuoteId}
        shipmentDetails={{
          origin: originLocation?.display_name || form.watch('origin_airport') || 'Origin',
          destination: destinationLocation?.display_name || form.watch('destination_airport') || 'Destination',
          originCountryCode: originLocation?.country_code,
          destinationCountryCode: destinationLocation?.country_code,
          mode: form.watch('mode'),
          pieces: cargoMetrics.pieces,
          weight: cargoMetrics.actualWeight,
          chargeableWeight: cargoMetrics.chargeableWeight,
          volumetricWeight: cargoMetrics.volumetricWeight,
          commodity: form.watch('cargo_type'),
          serviceScope: form.watch('service_scope'),
          incoterm: form.watch('incoterm'),
          dimensions: form.watch('dimensions'),
        }}
      />
    </div>
  );
}

"use client";

/**
 * SPOT Rate Entry Page
 * 
 * Streamlined 3-step flow:
 * 1. Intake (Submit) - Paste agent reply, AI analysis
 * 2. Review (Confirm) - Review assertions, fill missing fields, acknowledge
 * 3. Generate (Finalize) - View computed quote, finalize, generate PDF
 */

import { useState, useEffect } from "react";
import { useParams, useRouter, useSearchParams } from "next/navigation";
import { ArrowLeft, Package, CheckCircle2, Clock, AlertTriangle, FileText, Send, Check } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useSpotMode } from "@/hooks/use-spot-mode";
import {
    SpotAcknowledgementModal,
    ExpiredBanner,
    ReplyPasteCard,
    AssertionReviewCard
} from "@/components/spot";
import { SpotRateEntryForm } from "@/components/spot/SpotRateEntryForm";
import type { SPEChargeLine, CreateSPERequest, SPEShipmentContext, SPECommodity } from "@/lib/spot-types";
import type { ReplyAnalysisResult } from "@/lib/spot-types";

// Streamlined 3-step workflow
type Step = "intake" | "review" | "generate";

const STEPS: { id: Step; label: string; description: string }[] = [
    { id: "intake", label: "1. Submit", description: "Paste agent reply" },
    { id: "review", label: "2. Confirm", description: "Review & acknowledge" },
    { id: "generate", label: "3. Finalize", description: "Generate quote" },
];

export default function SpotRateEntryPage() {
    const params = useParams();
    const router = useRouter();
    const searchParams = useSearchParams();

    const speId = params.speId as string;
    const isNew = speId === "new";

    // Get shipment context from URL params (for new SPE)
    const originCountry = searchParams.get("origin_country") || "";
    const destCountry = searchParams.get("dest_country") || "";
    const originCode = searchParams.get("origin_code") || "";
    const destCode = searchParams.get("dest_code") || "";
    const commodity = (searchParams.get("commodity") || "GCR") as SPECommodity;
    const weight = parseFloat(searchParams.get("weight") || "0");
    const pieces = parseInt(searchParams.get("pieces") || "1");
    const triggerCode = searchParams.get("trigger_code") || "";
    const triggerText = searchParams.get("trigger_text") || "";
    const serviceScope = searchParams.get("service_scope") || "";
    const paymentTerm = searchParams.get("payment_term") || "PREPAID";
    const outputCurrency = searchParams.get("output_currency") || "PGK";
    const shipmentType = (searchParams.get("shipment_type") || "EXPORT") as "EXPORT" | "IMPORT" | "DOMESTIC";
    const missingComponents = searchParams.get("missing_components")?.split(",") || [];

    const { state, actions, derived } = useSpotMode();
    const { loadSPE } = actions;
    const [currentStep, setCurrentStep] = useState<Step>("intake");
    const [showAckModal, setShowAckModal] = useState(false);
    const [chargeLines, setChargeLines] = useState<Omit<SPEChargeLine, 'id'>[]>([]);
    const [analysisResult, setAnalysisResult] = useState<ReplyAnalysisResult | null>(null);

    // Load existing SPE
    useEffect(() => {
        if (speId && !isNew) {
            loadSPE(speId);
        }
    }, [isNew, speId, loadSPE]);

    // Determine current step from SPE state
    useEffect(() => {
        if (state.spe) {
            // Simplified 3-step flow logic
            if (state.flowState === "READY" || state.spe.acknowledgement) {
                setCurrentStep("generate");
            } else if (state.spe.charges.length > 0) {
                // If we have charges, we're in review step
                setCurrentStep(prev => prev === "review" ? prev : "review");
            } else {
                // Initial state - intake
                setCurrentStep("intake");
            }
        }
    }, [state.spe, state.flowState]);

    // Handle updating SPE with charges and auto-acknowledge
    const handleSaveAndAcknowledge = async (charges: Omit<SPEChargeLine, 'id'>[]) => {
        setChargeLines(charges);

        if (state.spe) {
            // First update charges
            const spe = await actions.updateSPE(state.spe.id, {
                charges,
                conditions: {
                    space_not_confirmed: true,
                    airline_acceptance_not_confirmed: true,
                    rate_validity_hours: 72,
                    conditional_charges_present: charges.some(c => c.conditional),
                }
            });

            if (spe) {
                // Auto-acknowledge (no longer a separate step)
                const success = await actions.submitAcknowledgement();
                if (success) {
                    setCurrentStep("generate");
                }
            }
        }
    };

    // Handle analysis complete from intake step - move directly to review
    const handleAnalysisComplete = (result: ReplyAnalysisResult) => {
        setAnalysisResult(result);
        setCurrentStep("review");
    };

    // Handle compute
    const handleCompute = async () => {
        const resolvedScope = serviceScope || "D2D";
        const resolvedPaymentTerm = paymentTerm || "PREPAID";
        const resolvedOutputCurrency = outputCurrency || "PGK";
        const result = await actions.computeQuote({
            quote_request: {
                payment_term: resolvedPaymentTerm,
                service_scope: resolvedScope,
                output_currency: resolvedOutputCurrency,
            },
        });

        if (result?.is_complete && result.spe_id) {
            // Navigate to quote result
            // For now, we'd need to integrate with actual quote creation
            console.log("SPOT quote computed:", result);
        }
    };

    // Handle create quote from SPE
    const handleCreateQuote = async () => {
        const resolvedScope = serviceScope || "D2D";
        const resolvedPaymentTerm = paymentTerm || "PREPAID";
        const resolvedOutputCurrency = outputCurrency || "PGK";

        const result = await actions.createQuote({
            payment_term: resolvedPaymentTerm,
            service_scope: resolvedScope,
            output_currency: resolvedOutputCurrency,
        });

        if (result?.success && result.quote_id) {
            router.push(`/quotes/${result.quote_id}`);
        }
    };

    // Render step progress
    const renderProgress = () => (
        <div className="flex items-center justify-between mb-8">
            {STEPS.map((step, index) => {
                const stepIndex = STEPS.findIndex(s => s.id === currentStep);
                const isCompleted = index < stepIndex;
                const isCurrent = step.id === currentStep;

                return (
                    <div key={step.id} className="flex items-center">
                        <div className={`
              flex items-center justify-center w-8 h-8 rounded-full text-sm font-medium
              ${isCompleted ? "bg-green-500 text-white" :
                                isCurrent ? "bg-primary text-primary-foreground" :
                                    "bg-muted text-muted-foreground"}
            `}>
                            {isCompleted ? <CheckCircle2 className="h-5 w-5" /> : index + 1}
                        </div>
                        <span className={`ml-2 text-sm ${isCurrent ? "font-medium" : "text-muted-foreground"}`}>
                            {step.label}
                        </span>
                        {index < STEPS.length - 1 && (
                            <div className={`w-12 h-0.5 mx-4 ${isCompleted ? "bg-green-500" : "bg-muted"}`} />
                        )}
                    </div>
                );
            })}
        </div>
    );

    // Handle flow state banners
    if (state.flowState === "EXPIRED" && state.spe) {
        return (
            <div className="container mx-auto max-w-4xl p-6">
                <ExpiredBanner
                    expiresAt={state.spe.expires_at}
                    onClone={() => router.push("/quotes/new")}
                />
            </div>
        );
    }

    if (state.spe?.status === "rejected") {
        return (
            <div className="container mx-auto max-w-4xl p-6">
                <RejectedBanner
                    comment={state.spe?.manager_approval?.comment}
                    onRevise={() => router.push("/quotes/new")}
                />
            </div>
        );
    }

    return (
        <div className="container mx-auto max-w-5xl space-y-6 p-6">
            {/* Context Header */}
            {isNew && triggerCode && (
                <div className="flex flex-col gap-2 rounded-lg border border-amber-200 bg-amber-50 p-4 shadow-sm">
                    <div className="flex items-center gap-2">
                        <Badge variant="outline" className="border-amber-500 bg-amber-100 text-amber-700">
                            SPOT Quote Required
                        </Badge>
                        <Badge variant="secondary" className="font-mono text-xs">
                            {triggerCode}
                        </Badge>
                    </div>
                    <p className="text-sm font-medium text-amber-900">
                        {triggerText || "This shipment requires manual rate sourcing."}
                    </p>
                </div>
            )}

            {/* Header */}
            <div className="flex items-center gap-4 mb-6">
                <Button variant="ghost" size="icon" onClick={() => router.back()}>
                    <ArrowLeft className="h-5 w-5" />
                </Button>
                <div>
                    <h1 className="text-2xl font-bold flex items-center gap-2">
                        <Package className="h-6 w-6 text-amber-600" />
                        {isNew ? "SPOT Rate Request" : "SPOT Pricing"}
                    </h1>
                    <p className="text-muted-foreground">
                        {isNew ? "Solicit and process manual rates" : `SPE: ${speId.slice(0, 8)}...`}
                    </p>
                </div>
                <Badge variant="outline" className="ml-auto text-amber-600 border-amber-400">
                    {triggerCode || state.spe?.spot_trigger_reason_code || "SPOT"}
                </Badge>
            </div>

            {/* Progress */}
            {renderProgress()}

            {/* Shipment Summary (Always visible) */}
            <Card className="mb-6">
                <CardHeader className="pb-3">
                    <CardTitle className="text-base font-semibold">Shipment Summary</CardTitle>
                </CardHeader>
                <CardContent>
                    <div className="grid grid-cols-4 gap-6 text-sm">
                        <div className="flex flex-col gap-1">
                            <span className="text-muted-foreground font-medium">Route</span>
                            <span className="font-bold text-slate-900">
                                {originCode || state.spe?.shipment.origin_code} → {destCode || state.spe?.shipment.destination_code}
                            </span>
                        </div>
                        <div className="flex flex-col gap-1">
                            <span className="text-muted-foreground font-medium">Commodity</span>
                            <span className="font-bold text-slate-900">{commodity || state.spe?.shipment.commodity}</span>
                        </div>
                        <div className="flex flex-col gap-1">
                            <span className="text-muted-foreground font-medium">Weight</span>
                            <span className="font-bold text-slate-900">{weight || state.spe?.shipment.total_weight_kg} kg</span>
                        </div>
                        <div className="flex flex-col gap-1">
                            <span className="text-muted-foreground font-medium">Pieces</span>
                            <span className="font-bold text-slate-900">{pieces || state.spe?.shipment.pieces}</span>
                        </div>
                    </div>
                </CardContent>
            </Card>

            {/* Error display */}
            {state.error && (
                <Card className="mb-6 border-red-200 bg-red-50">
                    <CardContent className="pt-4">
                        <div className="flex items-start gap-2 text-red-700">
                            <AlertTriangle className="h-5 w-5 mt-0.5" />
                            <p>{state.error}</p>
                        </div>
                    </CardContent>
                </Card>
            )}

            {/* Step Content */}

            {/* Step 1: Intake - Paste agent reply, AI analysis */}
            {currentStep === "intake" && (
                <ReplyPasteCard
                    speId={speId as string}
                    missingComponents={missingComponents}
                    onAnalysisComplete={handleAnalysisComplete}
                />
            )}

            {/* Step 2: Review - Assertion review, charge entry, currency selection, acknowledge */}
            {currentStep === "review" && (
                <div className="space-y-6">
                    {/* Assertion Review Card */}
                    {analysisResult && (
                        <AssertionReviewCard
                            result={analysisResult}
                            onConfirm={(refinedResult) => {
                                setAnalysisResult(refinedResult);
                            }}
                            onBack={() => setCurrentStep("intake")}
                        />
                    )}

                    {/* Rate Entry Form */}
                    <SpotRateEntryForm
                        onSubmit={handleSaveAndAcknowledge}
                        isLoading={state.isLoading}
                        initialCharges={state.spe?.charges || []}
                        suggestedCharges={analysisResult?.assertions}
                        shipmentType={shipmentType}
                        serviceScope={serviceScope}
                    />

                    {/* Acknowledgement checkbox */}
                    <Card>
                        <CardContent className="pt-4">
                            <div className="flex items-center gap-3">
                                <input
                                    type="checkbox"
                                    id="ack-checkbox"
                                    className="h-5 w-5 rounded border-gray-300"
                                    checked={showAckModal}
                                    onChange={(e) => setShowAckModal(e.target.checked)}
                                />
                                <label htmlFor="ack-checkbox" className="text-sm text-muted-foreground">
                                    I acknowledge this is a conditional SPOT quote and rates are not guaranteed until confirmed by carrier.
                                </label>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            )}

            {/* Step 3: Generate - Compute and finalize quote */}
            {currentStep === "generate" && (
                <>
                    {!state.quoteResult ? (
                        <Card>
                            <CardHeader>
                                <CardTitle className="flex items-center gap-2">
                                    <CheckCircle2 className="h-5 w-5 text-green-500" />
                                    Ready to Generate
                                </CardTitle>
                                <CardDescription>
                                    Review complete. Click below to compute and finalize the SPOT quote.
                                </CardDescription>
                            </CardHeader>
                            <CardContent>
                                <Button
                                    onClick={handleCompute}
                                    disabled={state.isLoading}
                                    className="w-full"
                                    size="lg"
                                >
                                    {state.isLoading ? (
                                        <Clock className="h-4 w-4 mr-2 animate-spin" />
                                    ) : (
                                        <Send className="h-4 w-4 mr-2" />
                                    )}
                                    Compute SPOT Quote
                                </Button>
                            </CardContent>
                        </Card>
                    ) : (
                        <Card>
                            <CardHeader>
                                <CardTitle className="flex items-center gap-2">
                                    <CheckCircle2 className="h-5 w-5 text-green-500" />
                                    SPOT Quote Preview
                                </CardTitle>
                                <CardDescription>
                                    Breakdown of charges based on SPOT entry and pricing logic.
                                </CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-6">
                                <div className="space-y-4">
                                    {[
                                        { title: "Origin Charges", bucket: "origin_charges" },
                                        { title: "Air Freight", bucket: ["freight_charges", "airfreight"] },
                                        { title: "Destination Charges", bucket: "destination_charges" }
                                    ].map((group) => {
                                        const groupLines = state.quoteResult!.lines?.filter(
                                            l => !l.is_informational && (Array.isArray(group.bucket) ? group.bucket.includes(l.bucket) : l.bucket === group.bucket)
                                        );

                                        if (!groupLines || groupLines.length === 0) return null;

                                        return (
                                            <div key={group.title} className="space-y-2">
                                                <div className="font-semibold text-xs uppercase tracking-wider text-muted-foreground border-b pb-1">
                                                    {group.title}
                                                </div>
                                                <div className="rounded-md divide-y border-x border-b border-t-0">
                                                    {groupLines.map((line, idx) => (
                                                        <div key={idx} className="flex justify-between p-3 text-sm bg-card hover:bg-accent/5 transition-colors">
                                                            <div>
                                                                <div className="font-medium">{line.description}</div>
                                                                <div className="text-xs text-muted-foreground">{line.source}</div>
                                                            </div>
                                                            <div className="text-right">
                                                                <div className="font-mono">{parseFloat(line.sell_pgk_incl_gst || "0").toLocaleString('en-US', { style: 'currency', currency: 'PGK' })}</div>
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>

                                {state.quoteResult.lines?.some(l => l.is_informational) && (
                                    <div className="space-y-2">
                                        <div className="font-semibold text-sm text-amber-600 flex items-center gap-2">
                                            <AlertTriangle className="h-4 w-4" />
                                            Conditions & Notes (Excluded from Total)
                                        </div>
                                        <div className="bg-amber-50 border border-amber-200 rounded-md p-3 space-y-2">
                                            {state.quoteResult.lines?.filter(l => l.is_informational).map((line, idx) => (
                                                <div key={idx} className="text-sm text-amber-800 flex justify-between">
                                                    <span>{line.description}</span>
                                                    <span className="italic text-xs opacity-70">Note</span>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                <Separator />

                                <div className="flex justify-between items-center text-lg font-bold">
                                    <div>Total (Inc. GST)</div>
                                    <div>
                                        {parseFloat(state.quoteResult.totals?.total_sell_pgk_incl_gst || "0").toLocaleString('en-US', { style: 'currency', currency: 'PGK' })}
                                    </div>
                                </div>

                                <div className="flex gap-2">
                                    <Button variant="outline" onClick={() => router.push('/quotes')} className="w-full">
                                        Back to Dashboard
                                    </Button>
                                    <Button
                                        onClick={handleCreateQuote}
                                        disabled={state.isLoading}
                                        className="w-full bg-green-600 hover:bg-green-700"
                                    >
                                        <Check className="h-4 w-4 mr-2" />
                                        Finalize Quote
                                    </Button>
                                </div>
                            </CardContent>
                        </Card>
                    )}
                </>
            )}
        </div>
    );
}

"use client";

import { useState } from "react";
import { QuoteComputeResult, SellLine } from "@/lib/types";
import {
    Card,
    CardContent,
    CardHeader,
    CardTitle,
} from "@/components/ui/card";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { Separator } from "@/components/ui/separator";
import { Badge } from "@/components/ui/badge";
import { ChevronDown, ChevronRight, Package, MapPin, ReceiptText, Plane } from "lucide-react";

interface QuoteFinancialBreakdownProps {
    result: QuoteComputeResult;
}

const formatCurrency = (amountStr: string | number | undefined, currency: string) => {
    const amount = typeof amountStr === 'number' ? amountStr : parseFloat(amountStr || "0");
    return new Intl.NumberFormat("en-US", {
        style: "currency",
        currency: currency,
    }).format(amount);
};

// Simplified currency display without symbol (for cleaner table display)
const formatAmount = (amountStr: string | number | undefined, currency: string) => {
    const amount = typeof amountStr === 'number' ? amountStr : parseFloat(amountStr || "0");
    const formatted = new Intl.NumberFormat("en-US", {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
    }).format(amount);
    return `${currency} ${formatted}`;
};

type BucketType = 'ORIGIN' | 'FREIGHT' | 'DESTINATION';
// Get bucket for a line
function getBucket(line: SellLine): BucketType {
    if (line.leg === 'MAIN' || line.leg === 'FREIGHT') return 'FREIGHT';
    if (line.leg === 'ORIGIN') return 'ORIGIN';
    return 'DESTINATION';
}

// Calculate bucket subtotal
function calculateBucketTotal(lines: SellLine[], field: 'sell_pgk_incl_gst' | 'sell_pgk' | 'sell_fcy' | 'sell_fcy_incl_gst'): number {
    return lines.reduce((sum, line) => {
        const value = parseFloat(line[field] || '0');
        return sum + value;
    }, 0);
}

// Determine if lines are FCY passthrough
function isFCYPassthrough(lines: SellLine[]): boolean {
    if (lines.length === 0) return false;
    const totalPgk = calculateBucketTotal(lines, 'sell_pgk');
    const totalFcy = calculateBucketTotal(lines, 'sell_fcy');
    return totalPgk === 0 && totalFcy > 0;
}

export default function QuoteFinancialBreakdown({ result }: QuoteFinancialBreakdownProps) {
    const { sell_lines, totals } = result;
    const sellCurrency = totals.currency;

    // Detect if this is an FCY passthrough quote
    const isOverallPassthrough = isFCYPassthrough(sell_lines);
    const displayCurrency = isOverallPassthrough ? (sell_lines[0]?.sell_currency || 'PGK') : 'PGK';

    // Separate informational (conditional) charges from priced lines
    const pricedLines = sell_lines.filter((line: SellLine) => !line.is_informational);
    const informationalLines = sell_lines.filter((line: SellLine) => line.is_informational);

    // Group PRICED lines by bucket (not informational ones)
    const buckets: Record<BucketType, SellLine[]> = {
        ORIGIN: [],
        FREIGHT: [],
        DESTINATION: [],
    };

    pricedLines.forEach((line: SellLine) => {
        const bucket = getBucket(line);
        buckets[bucket].push(line);
    });

    // Calculate totals (only from priced lines - backend already excludes informational)
    const totalExGst = isOverallPassthrough
        ? calculateBucketTotal(pricedLines, 'sell_fcy')
        : calculateBucketTotal(pricedLines, 'sell_pgk');
    const totalGst = isOverallPassthrough
        ? 0 // No GST for passthrough
        : pricedLines.reduce((sum, l) => sum + parseFloat(l.gst_amount || '0'), 0);
    const totalIncGst = totalExGst + totalGst;

    return (
        <Card className="overflow-hidden border-slate-200">
            <CardHeader className="pb-4 border-b border-slate-100">
                <div className="flex items-center justify-between">
                    <CardTitle className="text-lg font-semibold flex items-center gap-2">
                        <ReceiptText className="w-5 h-5 text-slate-400" />
                        Financial Breakdown
                    </CardTitle>
                    <span className="text-xs text-slate-400">
                        Computed {result.computation_date}
                    </span>
                </div>
            </CardHeader>
            <CardContent className="p-0">
                {/* ORIGIN CHARGES */}
                {buckets.ORIGIN.length > 0 && (
                    <BucketSection
                        title="Origin Charges"
                        lines={buckets.ORIGIN}
                        displayCurrency={displayCurrency}
                        isPassthrough={isOverallPassthrough}
                        icon={<Package className="w-4 h-4 text-blue-600" />}
                        colorClass="blue"
                    />
                )}
                {/* FREIGHT CHARGES */}
                {buckets.FREIGHT.length > 0 && (
                    <BucketSection
                        title="Freight Charges"
                        lines={buckets.FREIGHT}
                        displayCurrency={displayCurrency}
                        isPassthrough={isOverallPassthrough}
                        icon={<Plane className="w-4 h-4 text-blue-600" />}
                        colorClass="blue"
                    />
                )}

                {/* DESTINATION CHARGES */}
                {buckets.DESTINATION.length > 0 && (
                    <BucketSection
                        title="Destination Charges"
                        lines={buckets.DESTINATION}
                        displayCurrency={displayCurrency}
                        isPassthrough={isOverallPassthrough}
                        icon={<MapPin className="w-4 h-4 text-blue-600" />}
                        colorClass="blue"
                    />
                )}

                {/* Totals Section */}
                <div className="p-6 bg-slate-50 border-t border-slate-200">
                    <div className="flex flex-col items-end space-y-2">
                        <div className="flex justify-between w-full max-w-xs text-sm">
                            <span className="text-slate-500">Total Sell (Ex GST)</span>
                            <span className="font-mono font-medium">
                                {formatAmount(totalExGst, displayCurrency)}
                            </span>
                        </div>
                        <div className="flex justify-between w-full max-w-xs text-sm">
                            <span className="text-slate-500">Total GST</span>
                            <span className="font-mono">
                                {formatAmount(totalGst, displayCurrency)}
                            </span>
                        </div>
                        <Separator className="w-full max-w-xs my-2" />
                        <div className="flex justify-between w-full max-w-xs items-end">
                            <span className="text-sm font-medium text-slate-700">Total Quote Amount</span>
                            <div className="text-right">
                                <span className="block text-2xl font-bold text-blue-600">
                                    {displayCurrency} {totalIncGst.toLocaleString('en-US', { minimumFractionDigits: 2 })}
                                </span>
                                <span className="text-[10px] text-slate-400 uppercase">
                                    {displayCurrency} (INC GST)
                                </span>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Conditional Charges Footnotes */}
                {informationalLines.length > 0 && (
                    <div className="p-4 bg-amber-50/50 border-t border-amber-200">
                        <div className="flex items-start gap-2">
                            <span className="text-amber-600 text-xs font-semibold uppercase tracking-wide">Conditions & Notes</span>
                        </div>
                        <ul className="mt-2 space-y-1">
                            {informationalLines.map((line, idx) => (
                                <li key={idx} className="text-xs text-amber-800 flex items-start gap-2">
                                    <span className="text-amber-500">•</span>
                                    <span>{line.description} — <em className="text-amber-600">if applicable</em></span>
                                </li>
                            ))}
                        </ul>
                    </div>
                )}
            </CardContent>
        </Card>
    );
}

// Helper for section styling - Refined for visual hierarchy & lighter feel
function getSectionStyle() {
    return {
        wrapper: "mb-6 rounded-lg border border-slate-200 overflow-hidden bg-white shadow-sm", // Clean card style
        header: "bg-white hover:bg-slate-50 border-b border-slate-100 transition-colors", // Lighter header
        title: "text-slate-900", // Stronger title contrast
        iconBg: "bg-blue-50 text-blue-600", // Subtler icon background
        borderLeft: "border-l-[4px] border-l-blue-500" // Consistent accent
    };
}

// Bucket Section Component
function BucketSection({
    title,
    lines,
    displayCurrency,
    isPassthrough,
    icon,
    // colorClass prop is present in parent but ignored here to enforce standardized Blue theme
}: {
    title: string;
    lines: SellLine[];
    displayCurrency: string;
    isPassthrough: boolean;
    icon: React.ReactNode;
    colorClass?: string;
}) {
    // Default to collapsed for Freight/Dest, maybe Expanded for Origin? 
    // User requested default collapsed previously.
    const [isExpanded, setIsExpanded] = useState(false);
    const styles = getSectionStyle();

    // Calculate subtotal for this bucket
    const bucketTotal = isPassthrough
        ? calculateBucketTotal(lines, 'sell_fcy')
        : calculateBucketTotal(lines, 'sell_pgk');

    return (
        <div className={styles.wrapper}>
            <button
                onClick={() => setIsExpanded(!isExpanded)}
                className={`w-full flex items-center justify-between p-5 ${styles.header} ${styles.borderLeft}`}
            >
                <div className="flex items-center gap-4">
                    <div className={`p-2 rounded-lg ${styles.iconBg}`}>
                        {icon}
                    </div>
                    <div className="text-left">
                        <div className="flex items-center gap-3">
                            <h3 className={`text-base font-bold tracking-tight ${styles.title}`}>
                                {title}
                            </h3>
                            {!isExpanded && (
                                <span className="flex items-center justify-center bg-slate-100 text-slate-500 text-[11px] font-semibold h-6 px-2 rounded-full">
                                    {lines.length}
                                </span>
                            )}
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-6">
                    <div className="text-right">
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mb-0.5">Subtotal</p>
                        <p className="text-base font-bold text-slate-900 mono-font">
                            {formatAmount(bucketTotal, displayCurrency)}
                        </p>
                    </div>
                    {isExpanded ? (
                        <ChevronDown className="w-5 h-5 text-slate-400" />
                    ) : (
                        <ChevronRight className="w-5 h-5 text-slate-400" />
                    )}
                </div>
            </button>

            {isExpanded && (
                <div className="p-6 pt-2 bg-slate-50/30">
                    <div className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden">
                        <Table>
                            <TableHeader className="bg-slate-50/80">
                                <TableRow className="hover:bg-transparent border-b border-slate-100">
                                    <TableHead className="w-[50%] h-10 text-[11px] font-bold uppercase tracking-wider text-slate-500 pl-6">Description</TableHead>
                                    <TableHead className="text-right h-10 text-[11px] font-bold uppercase tracking-wider text-slate-500">Sell (Ex GST)</TableHead>
                                    <TableHead className="text-center h-10 text-[11px] font-bold uppercase tracking-wider text-slate-500 w-[120px]">GST</TableHead>
                                    <TableHead className="text-right h-10 text-[11px] font-bold uppercase tracking-wider text-slate-500 pr-6">Total</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {lines.map((line, index) => (
                                    <ChargeRow
                                        key={index}
                                        line={line}
                                        displayCurrency={displayCurrency}
                                        isPassthrough={isPassthrough}
                                    />
                                ))}
                            </TableBody>
                        </Table>
                    </div>
                </div>
            )}
        </div>
    );
}

// Individual Charge Row
function ChargeRow({
    line,
    displayCurrency,
    isPassthrough
}: {
    line: SellLine;
    displayCurrency: string;
    isPassthrough: boolean;
}) {
    const sellExGst = isPassthrough ? line.sell_fcy : line.sell_pgk;
    const gstAmountVal = parseFloat((isPassthrough ? '0' : line.gst_amount) || '0');

    // Determine GST display text
    let gstDisplay: React.ReactNode = '—';
    if (!isPassthrough) {
        if (gstAmountVal > 0) {
            gstDisplay = formatAmount(gstAmountVal, displayCurrency);
        } else {
            // Updated to non-interactive muted text
            gstDisplay = <span className="text-[10px] font-medium text-slate-400 uppercase tracking-wide">Exempt</span>;
        }
    }

    const total = isPassthrough
        ? line.sell_fcy
        : (line.sell_pgk_incl_gst || line.sell_pgk);

    return (
        <TableRow className="hover:bg-blue-50/30 border-b border-slate-50 last:border-0 transition-colors">
            <TableCell className="py-4 pl-6">
                <div className="font-medium text-slate-700 text-sm">
                    {line.description}
                </div>
                {/* Reduced emphasis on line codes - secondary info */}
                <div className="text-[10px] text-slate-400 uppercase tracking-wider mt-1 font-mono opacity-80">
                    {line.component || 'MISC'}
                </div>
            </TableCell>
            <TableCell className="text-right font-mono text-sm text-slate-600 py-4">
                {formatAmount(sellExGst, displayCurrency)}
            </TableCell>
            <TableCell className="text-center py-4">
                {/* GST Column centered and clean */}
                <div className="flex items-center justify-center">
                    {gstDisplay}
                </div>
            </TableCell>
            <TableCell className="text-right font-mono text-sm font-bold text-slate-800 py-4 pr-6">
                {formatAmount(total, displayCurrency)}
            </TableCell>
        </TableRow>
    );
}

"use client";

import React, { useState, useEffect, useMemo } from "react";
import { Plane, Package, MapPin, Calculator, Loader2, CheckCircle, Lock } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Badge } from "@/components/ui/badge";
import { BucketChargeSection } from "@/components/pricing/BucketChargeSection";
import { FreeformLineEditor, getDefaultCurrencyForCountry } from "@/components/pricing/FreeformLineEditor";
import { AIRateIntakeModal } from "@/components/AIRateIntakeModal";
import {
    getSpotChargesForQuote,
    saveSpotChargesForQuote,
    calculateSpotCharges,
} from "@/lib/api";
import type {
    SpotChargeLine,
    SpotChargeBucket,
    SpotChargesGrouped,
    SpotChargesCalculateResponse,
    V3QuoteComputeResponse,
} from "@/lib/types";

interface BucketSourcingViewProps {
    quote: V3QuoteComputeResponse;
    onFinalizeSuccess: () => void;
}

interface BucketConfig {
    bucket: SpotChargeBucket;
    title: string;
    icon: React.ReactNode;
    editable: boolean;
    subtotal?: string;
    subtotalNote?: string;
}

/**
 * Determine which buckets should be editable based on shipment context.
 * 
 * Rules:
 * | Direction | Scope | Payment | Buckets to Show |
 * |-----------|-------|---------|-----------------|
 * | Import | Any | Collect | Origin + Freight + Dest |
 * | Import | A2D | Prepaid | Dest only |
 * | Export | D2A | Prepaid | None (auto-rated) |
 * | Export | D2D (DAP) | Prepaid | Dest only |
 * | Export | D2A | Collect | Origin (if missing) |
 */
function getEditableBuckets(quote: V3QuoteComputeResponse): Set<SpotChargeBucket> {
    const direction = quote.shipment_type; // IMPORT or EXPORT
    const paymentTerm = quote.payment_term; // PREPAID or COLLECT
    const scope = quote.service_scope; // D2D, A2D, D2A

    if (direction === "IMPORT") {
        if (paymentTerm === "COLLECT") {
            // Import Collect - all buckets editable
            return new Set(["ORIGIN", "FREIGHT", "DESTINATION"]);
        }
        if (paymentTerm === "PREPAID" && scope === "A2D") {
            // Import Prepaid A2D - destination only
            return new Set(["DESTINATION"]);
        }
        // Default for other imports
        return new Set(["ORIGIN", "FREIGHT", "DESTINATION"]);
    }

    if (direction === "EXPORT") {
        if (paymentTerm === "PREPAID") {
            if (scope === "D2D") {
                // Export Prepaid D2D (DAP) - destination only
                return new Set(["DESTINATION"]);
            }
            if (scope === "D2A") {
                // Export Prepaid D2A - none (auto-rated)
                return new Set();
            }
        }
        if (paymentTerm === "COLLECT" && scope === "D2A") {
            // Export Collect D2A - origin only if missing
            return new Set(["ORIGIN"]);
        }
        // Default for other exports
        return new Set(["DESTINATION"]);
    }

    // Default fallback
    return new Set(["ORIGIN", "FREIGHT", "DESTINATION"]);
}

/**
 * Check if quote is Import Prepaid A2D DAP (passthrough pricing)
 */
function isA2DDAPQuote(quote: V3QuoteComputeResponse): boolean {
    return (
        quote.shipment_type === "IMPORT" &&
        quote.payment_term === "PREPAID" &&
        quote.service_scope === "A2D" &&
        quote.incoterm === "DAP"
    );
}

/**
 * Determine which buckets should be VISIBLE (not just editable).
 * For A2D DAP quotes, Origin and Freight are completely hidden.
 * 
 * | Direction | Scope | Payment | Incoterm | Visible Buckets |
 * |-----------|-------|---------|----------|-----------------|
 * | Import | A2D | Prepaid | DAP | Dest only |
 * | Export | D2D | Prepaid | DAP | Dest only |
 * | Other | Any | Any | Any | All |
 */
function getVisibleBuckets(quote: V3QuoteComputeResponse): Set<SpotChargeBucket> {
    // Import Prepaid A2D DAP - only show destination
    if (isA2DDAPQuote(quote)) {
        return new Set(["DESTINATION"]);
    }

    // Export D2D DAP Prepaid - only show destination
    if (
        quote.shipment_type === "EXPORT" &&
        quote.payment_term === "PREPAID" &&
        quote.service_scope === "D2D" &&
        quote.incoterm === "DAP"
    ) {
        return new Set(["DESTINATION"]);
    }

    // Export D2A Prepaid (any incoterm) - hide destination entirely
    // D2A = Door to Airport, service ends at destination airport, no destination charges
    if (
        quote.shipment_type === "EXPORT" &&
        quote.payment_term === "PREPAID" &&
        quote.service_scope === "D2A"
    ) {
        return new Set(["ORIGIN", "FREIGHT"]);
    }

    // Default: all buckets visible (editability is separate)
    return new Set(["ORIGIN", "FREIGHT", "DESTINATION"]);
}

/**
 * Get subtotals for non-editable buckets from quote lines.
 */
function getBucketSubtotals(quote: V3QuoteComputeResponse): Record<SpotChargeBucket, { amount: string; currency: string }> {
    const lines = quote.latest_version?.lines || [];

    const totals: Record<SpotChargeBucket, { amount: number; currency: string }> = {
        ORIGIN: { amount: 0, currency: "PGK" },
        FREIGHT: { amount: 0, currency: "PGK" },
        DESTINATION: { amount: 0, currency: "PGK" },
    };

    for (const line of lines) {
        const leg = line.service_component?.leg;
        const sellPgk = parseFloat(line.sell_pgk) || 0;

        if (leg === "ORIGIN") {
            totals.ORIGIN.amount += sellPgk;
        } else if (leg === "MAIN" || leg === "FREIGHT") {
            totals.FREIGHT.amount += sellPgk;
        } else if (leg === "DESTINATION") {
            totals.DESTINATION.amount += sellPgk;
        }
    }

    return {
        ORIGIN: { amount: totals.ORIGIN.amount.toFixed(2), currency: "PGK" },
        FREIGHT: { amount: totals.FREIGHT.amount.toFixed(2), currency: "PGK" },
        DESTINATION: { amount: totals.DESTINATION.amount.toFixed(2), currency: "PGK" },
    };
}

/**
 * Extract destination country code from quote.
 * Handles formats like:
 * - "Brisbane (BNE), AU"
 * - "BNE"
 * - "Port Moresby (POM), PG"
 */
function getDestinationCountryCode(quote: V3QuoteComputeResponse): string | undefined {
    const destLocation = quote.destination_location;
    if (typeof destLocation !== "string" || !destLocation) return undefined;

    // Try to extract country code from end of string (e.g., ", AU" or ", PG")
    const countryMatch = destLocation.match(/,\s*([A-Z]{2})\s*$/i);
    if (countryMatch) {
        return countryMatch[1].toUpperCase();
    }

    // Try to extract IATA code in parentheses (e.g., "(BNE)")
    const iataMatch = destLocation.match(/\(([A-Z]{3})\)/i);
    const iataCode = iataMatch?.[1]?.toUpperCase();

    // Fallback: if the whole string is just an IATA code
    const plainIata = destLocation.length === 3 ? destLocation.toUpperCase() : iataCode;

    if (plainIata) {
        // Common airport codes to country mapping
        const airportCountryMap: Record<string, string> = {
            // Australia
            BNE: "AU", SYD: "AU", MEL: "AU", PER: "AU", ADL: "AU", CBR: "AU",
            DRW: "AU", CNS: "AU", OOL: "AU", HBA: "AU",
            // USA
            LAX: "US", JFK: "US", SFO: "US", ORD: "US", MIA: "US", DFW: "US",
            ATL: "US", SEA: "US", DEN: "US",
            // China
            PVG: "CN", PEK: "CN", CAN: "CN", SZX: "CN", CTU: "CN",
            // Hong Kong
            HKG: "HK",
            // Singapore
            SIN: "SG",
            // New Zealand
            AKL: "NZ", WLG: "NZ", CHC: "NZ",
            // UK
            LHR: "GB", LGW: "GB", MAN: "GB", STN: "GB",
            // PNG
            POM: "PG", LAE: "PG",
            // Japan
            NRT: "JP", HND: "JP", KIX: "JP",
            // South Korea
            ICN: "KR", GMP: "KR",
            // Thailand
            BKK: "TH", DMK: "TH",
            // Malaysia
            KUL: "MY",
            // Indonesia
            CGK: "ID", DPS: "ID",
            // Philippines
            MNL: "PH", CEB: "PH",
            // India
            DEL: "IN", BOM: "IN", BLR: "IN",
            // UAE
            DXB: "AE", AUH: "AE",
        };
        return airportCountryMap[plainIata];
    }

    return undefined;
}


export function BucketSourcingView({ quote, onFinalizeSuccess }: BucketSourcingViewProps) {
    const [charges, setCharges] = useState<SpotChargesGrouped>({
        ORIGIN: [],
        FREIGHT: [],
        DESTINATION: [],
    });
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [calculating, setCalculating] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [calcResult, setCalcResult] = useState<SpotChargesCalculateResponse | null>(null);
    const [editorOpen, setEditorOpen] = useState(false);
    const [editingBucket, setEditingBucket] = useState<SpotChargeBucket>("DESTINATION");
    const [editingLine, setEditingLine] = useState<SpotChargeLine | null>(null);
    const [aiIntakeOpen, setAiIntakeOpen] = useState(false);

    // Determine which buckets are editable, visible, and auto-rated subtotals
    const editableBuckets = useMemo(() => getEditableBuckets(quote), [quote]);
    const visibleBuckets = useMemo(() => getVisibleBuckets(quote), [quote]);
    const bucketSubtotals = useMemo(() => getBucketSubtotals(quote), [quote]);
    const destinationCountryCode = useMemo(() => getDestinationCountryCode(quote), [quote]);
    const isPassthroughQuote = useMemo(() => isA2DDAPQuote(quote), [quote]);

    // Build bucket config with visibility rules
    const bucketConfigs: BucketConfig[] = useMemo(() => {
        const allBuckets: BucketConfig[] = [
            {
                bucket: "ORIGIN" as SpotChargeBucket,
                title: "Origin Charges",
                icon: <MapPin className="h-5 w-5" />,
                editable: editableBuckets.has("ORIGIN"),
                subtotal: bucketSubtotals.ORIGIN.amount,
                subtotalNote: editableBuckets.has("ORIGIN") ? undefined : "auto-rated",
            },
            {
                bucket: "FREIGHT" as SpotChargeBucket,
                title: "Freight",
                icon: <Plane className="h-5 w-5" />,
                editable: editableBuckets.has("FREIGHT"),
                subtotal: bucketSubtotals.FREIGHT.amount,
                subtotalNote: editableBuckets.has("FREIGHT") ? undefined : "auto-rated",
            },
            {
                bucket: "DESTINATION" as SpotChargeBucket,
                title: "Destination Charges",
                icon: <Package className="h-5 w-5" />,
                editable: editableBuckets.has("DESTINATION"),
                subtotal: bucketSubtotals.DESTINATION.amount,
                subtotalNote: editableBuckets.has("DESTINATION") ? undefined : "auto-rated",
            },
        ];

        // Filter to only visible buckets (hides Origin/Freight for A2D DAP)
        return allBuckets.filter(b => visibleBuckets.has(b.bucket));
    }, [editableBuckets, bucketSubtotals, visibleBuckets]);

    // Flatten all lines for the editor's target line selection
    const allLines = useMemo(() => {
        return [...charges.ORIGIN, ...charges.FREIGHT, ...charges.DESTINATION];
    }, [charges]);

    // Only count editable bucket lines
    const editableLines = useMemo(() => {
        let lines: SpotChargeLine[] = [];
        if (editableBuckets.has("ORIGIN")) lines = [...lines, ...charges.ORIGIN];
        if (editableBuckets.has("FREIGHT")) lines = [...lines, ...charges.FREIGHT];
        if (editableBuckets.has("DESTINATION")) lines = [...lines, ...charges.DESTINATION];
        return lines;
    }, [charges, editableBuckets]);

    // Load existing spot charges
    useEffect(() => {
        const loadCharges = async () => {
            setLoading(true);
            try {
                const response = await getSpotChargesForQuote(quote.id);
                setCharges(response.charges);
            } catch (err) {
                console.error("Failed to load spot charges:", err);
                // Not an error - just means no charges yet
            } finally {
                setLoading(false);
            }
        };
        loadCharges();
    }, [quote.id]);

    // Reload charges after AI intake success
    const handleAiIntakeSuccess = async () => {
        try {
            const response = await getSpotChargesForQuote(quote.id);
            setCharges(response.charges);
        } catch (err) {
            console.error("Failed to reload spot charges:", err);
        }
    };

    const handleAddLine = (bucket: SpotChargeBucket) => {
        setEditingBucket(bucket);
        setEditingLine(null);
        setEditorOpen(true);
    };

    const handleEditLine = (line: SpotChargeLine) => {
        setEditingBucket(line.bucket);
        setEditingLine(line);
        setEditorOpen(true);
    };

    const handleDeleteLine = (bucket: SpotChargeBucket, lineId: string) => {
        setCharges((prev) => ({
            ...prev,
            [bucket]: prev[bucket].filter((l) => l.id !== lineId),
        }));
    };

    const handleSaveLine = (line: SpotChargeLine) => {
        setCharges((prev) => {
            const bucket = line.bucket;
            const existing = prev[bucket];

            if (line.id) {
                // Update existing line
                return {
                    ...prev,
                    [bucket]: existing.map((l) => (l.id === line.id ? line : l)),
                };
            } else {
                // Add new line with temporary ID
                const newLine = { ...line, id: `temp-${Date.now()}` };
                return {
                    ...prev,
                    [bucket]: [...existing, newLine],
                };
            }
        });
        setEditorOpen(false);
    };

    const handleSaveAndCalculate = async () => {
        setError(null);
        setSaving(true);

        try {
            // For fully auto-rated quotes (no editable buckets), 
            // just move from INCOMPLETE to DRAFT since all rates are on rate cards
            if (editableBuckets.size === 0) {
                const token = localStorage.getItem("token");

                // Update status from INCOMPLETE to DRAFT
                // (the quote is complete, just needs to be marked as such)
                const updateResponse = await fetch(
                    `${process.env.NEXT_PUBLIC_API_URL || "http://127.0.0.1:8000"}/api/quotes/v3/quotes/${quote.id}/`,
                    {
                        method: "PATCH",
                        headers: {
                            "Content-Type": "application/json",
                            "Authorization": `Token ${token}`,
                        },
                        body: JSON.stringify({ status: "DRAFT" }),
                    }
                );

                if (!updateResponse.ok) {
                    const errorData = await updateResponse.json().catch(() => ({}));
                    const errorMsg = errorData.detail || errorData.error || JSON.stringify(errorData) || `HTTP ${updateResponse.status}`;
                    throw new Error(`Failed to update quote status: ${errorMsg}`);
                }

                // Notify parent of success
                onFinalizeSuccess();
                return;
            }

            // For quotes with editable buckets, use the spot charge flow
            const allCharges = [...charges.ORIGIN, ...charges.FREIGHT, ...charges.DESTINATION];
            await saveSpotChargesForQuote(quote.id, allCharges);

            // Now calculate
            setCalculating(true);
            const result = await calculateSpotCharges(quote.id);
            setCalcResult(result);

            // Notify parent of success
            onFinalizeSuccess();
        } catch (err) {
            const msg = err instanceof Error ? err.message : "Failed to calculate";
            setError(msg);
        } finally {
            setSaving(false);
            setCalculating(false);
        }
    };

    const hasCharges = editableLines.length > 0 || editableBuckets.size === 0;
    const noEditableBuckets = editableBuckets.size === 0;

    if (loading) {
        return (
            <Card>
                <CardContent className="flex items-center justify-center py-12">
                    <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
                </CardContent>
            </Card>
        );
    }

    return (
        <div className="space-y-4">
            <Card className="border-amber-200 bg-amber-50/30">
                <CardHeader className="pb-3">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-amber-100 rounded-full">
                            <Calculator className="h-5 w-5 text-amber-700" />
                        </div>
                        <div>
                            <CardTitle className="text-lg text-amber-800">
                                Enter Spot Rates by Bucket
                            </CardTitle>
                            <CardDescription>
                                {noEditableBuckets
                                    ? "All charges are auto-rated. Review and finalize."
                                    : "Add charges from the agent quote into the appropriate cost buckets."}
                            </CardDescription>
                        </div>
                        {/* AI Rate Intake Button - only show when there are editable buckets */}
                        {!noEditableBuckets && (
                            <Button
                                variant="outline"
                                onClick={() => setAiIntakeOpen(true)}
                                className="border-amber-300 text-amber-800 hover:bg-amber-100"
                            >
                                AI Rate Intake
                            </Button>
                        )}
                    </div>
                </CardHeader>
            </Card>

            {/* Bucket Sections */}
            <div className="space-y-4">
                {bucketConfigs.map(({ bucket, title, icon, editable, subtotal, subtotalNote }) => (
                    editable ? (
                        <BucketChargeSection
                            key={bucket}
                            bucket={bucket}
                            title={title}
                            icon={icon}
                            lines={charges[bucket]}
                            onAddLine={() => handleAddLine(bucket)}
                            onEditLine={handleEditLine}
                            onDeleteLine={(lineId) => handleDeleteLine(bucket, lineId)}
                        />
                    ) : (
                        // Non-editable bucket - show subtotal only
                        <Card key={bucket} className="opacity-60">
                            <CardHeader className="py-3 px-4 flex flex-row items-center justify-between bg-muted/30">
                                <div className="flex items-center gap-3">
                                    <div className="p-1.5 rounded-md bg-muted text-muted-foreground">
                                        {icon}
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <h3 className="font-semibold text-muted-foreground">{title}</h3>
                                        <Lock className="h-3.5 w-3.5 text-muted-foreground" />
                                    </div>
                                </div>
                                <div className="flex items-center gap-2">
                                    <Badge variant="outline" className="bg-background">
                                        {subtotal} PGK
                                    </Badge>
                                    {subtotalNote && (
                                        <span className="text-xs text-muted-foreground">({subtotalNote})</span>
                                    )}
                                </div>
                            </CardHeader>
                        </Card>
                    )
                ))}
            </div>

            {/* Calculation Result */}
            {calcResult && (
                <Card className="border-emerald-200 bg-emerald-50/30">
                    <CardHeader className="pb-3">
                        <div className="flex items-center gap-2">
                            <CheckCircle className="h-5 w-5 text-emerald-600" />
                            <CardTitle className="text-lg text-emerald-800">
                                Calculation Complete
                            </CardTitle>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            <div>
                                <div className="text-xs text-muted-foreground uppercase">Origin</div>
                                <div className="font-mono font-semibold">
                                    {parseFloat(calcResult.totals.origin_sell_pgk).toFixed(2)} PGK
                                </div>
                            </div>
                            <div>
                                <div className="text-xs text-muted-foreground uppercase">Freight</div>
                                <div className="font-mono font-semibold">
                                    {parseFloat(calcResult.totals.freight_sell_pgk).toFixed(2)} PGK
                                </div>
                            </div>
                            <div>
                                <div className="text-xs text-muted-foreground uppercase">Destination</div>
                                <div className="font-mono font-semibold">
                                    {parseFloat(calcResult.totals.destination_sell_pgk).toFixed(2)} PGK
                                </div>
                            </div>
                            <div className="border-l pl-4">
                                <div className="text-xs text-muted-foreground uppercase">Grand Total</div>
                                <div className="font-mono font-bold text-lg">
                                    {parseFloat(calcResult.totals.grand_total_pgk).toFixed(2)} PGK
                                </div>
                                {calcResult.totals.grand_total_fcy && (
                                    <div className="font-mono text-sm text-muted-foreground">
                                        {parseFloat(calcResult.totals.grand_total_fcy).toFixed(2)} {calcResult.quoting_currency}
                                    </div>
                                )}
                            </div>
                        </div>
                        <div className="mt-3 flex items-center gap-2 text-xs text-muted-foreground">
                            <Badge variant="outline">CW: {calcResult.chargeable_weight} kg</Badge>
                            <Badge variant="outline">Quote: {calcResult.quoting_currency}</Badge>
                        </div>
                    </CardContent>
                </Card>
            )}

            {/* Error Alert */}
            {error && (
                <Alert variant="destructive">
                    <AlertDescription>{error}</AlertDescription>
                </Alert>
            )}

            {/* Action Buttons */}
            <Card>
                <CardContent className="p-4">
                    <div className="flex items-center justify-between">
                        <div className="text-sm text-muted-foreground">
                            {noEditableBuckets
                                ? "All charges auto-rated — ready to finalize"
                                : editableLines.length > 0
                                    ? `${editableLines.length} charge line${editableLines.length > 1 ? "s" : ""} ready`
                                    : "Add charges to calculate"}
                        </div>
                        <Button
                            size="lg"
                            disabled={(!hasCharges && editableBuckets.size > 0) || saving || calculating}
                            onClick={handleSaveAndCalculate}
                            className="shadow-md"
                        >
                            {(saving || calculating) && (
                                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                            )}
                            {saving ? "Saving..." : calculating ? "Calculating..." : noEditableBuckets ? "Confirm & View Quote" : "Calculate & Finalize"}
                        </Button>
                    </div>
                </CardContent>
            </Card>

            {/* Line Editor Dialog */}
            <FreeformLineEditor
                open={editorOpen}
                onClose={() => setEditorOpen(false)}
                onSave={handleSaveLine}
                bucket={editingBucket}
                existingLine={editingLine}
                existingLines={allLines}
                destinationCountryCode={destinationCountryCode}
            />

            {/* AI Rate Intake Modal */}
            <AIRateIntakeModal
                open={aiIntakeOpen}
                onOpenChange={setAiIntakeOpen}
                quoteId={quote.id}
                onSuccess={handleAiIntakeSuccess}
            />
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { AlertTriangle } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogFooter,
} from "@/components/ui/dialog";
import { Alert, AlertDescription } from "@/components/ui/alert";
import type {
    SpotChargeLine,
    SpotChargeBucket,
    SpotChargeUnitBasis,
    SpotChargePercentAppliesTo,
} from "@/lib/types";

const CURRENCIES = ["USD", "AUD", "SGD", "CNY", "EUR", "GBP", "NZD", "PGK"] as const;

// Removed PER_MAN as requested
const UNIT_BASIS_OPTIONS: { value: SpotChargeUnitBasis; label: string }[] = [
    { value: "PER_SHIPMENT", label: "Per Shipment" },
    { value: "PER_KG", label: "Per KG (rate × chargeable weight)" },
    { value: "PER_AWB", label: "Per AWB" },
    { value: "MINIMUM", label: "Minimum Charge" },
    { value: "PER_HOUR", label: "Per Hour" },
    { value: "PERCENTAGE", label: "Percentage (%)" },
    { value: "OTHER", label: "Other" },
];

const PERCENT_APPLIES_TO_OPTIONS: { value: SpotChargePercentAppliesTo; label: string }[] = [
    { value: "SPECIFIC_LINE", label: "Specific Charge Line" },
    { value: "BUCKET_ORIGIN", label: "Origin Bucket Total" },
    { value: "BUCKET_FREIGHT", label: "Freight Bucket Total" },
    { value: "BUCKET_DESTINATION", label: "Destination Bucket Total" },
    { value: "BUCKET_TOTAL", label: "All Buckets Total" },
];

// Banned generic patterns for description validation
const BANNED_PATTERNS = [
    /^fee$/i, /^fees$/i, /^cost$/i, /^costs$/i, /^charge$/i, /^charges$/i,
    /^ok$/i, /^-$/i, /^\.$/i, /^\?$/i, /^tbd$/i, /^n\/a$/i, /^na$/i,
];

// Description placeholder examples
const DESCRIPTION_PLACEHOLDER = "e.g., Sydney Agent Handling + Documentation";

// Get default currency based on destination country
export function getDefaultCurrencyForCountry(countryCode: string | undefined): string {
    if (!countryCode) return "USD";
    const code = countryCode.toUpperCase();
    switch (code) {
        case "AU": return "AUD";
        case "US": return "USD";
        case "CN": return "CNY";
        case "NZ": return "NZD";
        case "SG": return "SGD";
        case "GB": return "GBP";
        case "PG": return "PGK";
        default: return "USD";
    }
}

// Validate description
function validateDescription(desc: string): { valid: boolean; error?: string } {
    const trimmed = desc.trim();

    if (trimmed.length < 15) {
        return { valid: false, error: "Description too short — please enter at least 15 characters." };
    }

    // Check banned patterns
    for (const pattern of BANNED_PATTERNS) {
        if (pattern.test(trimmed)) {
            return { valid: false, error: "Description too vague — please enter what the agent actually wrote." };
        }
    }

    // Check for single word
    const words = trimmed.split(/\s+/).filter(w => w.length > 0);
    if (words.length < 2) {
        return { valid: false, error: "Please provide more detail — at least 2 words required." };
    }

    return { valid: true };
}

interface FreeformLineEditorProps {
    open: boolean;
    onClose: () => void;
    onSave: (line: SpotChargeLine) => void;
    bucket: SpotChargeBucket;
    existingLine?: SpotChargeLine | null;
    existingLines?: SpotChargeLine[];
    destinationCountryCode?: string;
}

export function FreeformLineEditor({
    open,
    onClose,
    onSave,
    bucket,
    existingLine,
    existingLines = [],
    destinationCountryCode,
}: FreeformLineEditorProps) {
    const isEditing = !!existingLine;

    // Get default currency based on destination
    const defaultCurrency = getDefaultCurrencyForCountry(destinationCountryCode);

    const [description, setDescription] = useState("");
    const [amount, setAmount] = useState("");
    const [minCharge, setMinCharge] = useState("");
    const [currency, setCurrency] = useState<string>(defaultCurrency);
    const [unitBasis, setUnitBasis] = useState<SpotChargeUnitBasis>("PER_SHIPMENT");
    const [percentage, setPercentage] = useState("");
    const [percentAppliesTo, setPercentAppliesTo] = useState<SpotChargePercentAppliesTo>("BUCKET_FREIGHT");
    const [targetLineId, setTargetLineId] = useState<string>("");
    const [notes, setNotes] = useState("");
    const [descriptionError, setDescriptionError] = useState<string | null>(null);

    const isPerKg = unitBasis === "PER_KG";

    // Check if currency is unusual for destination
    const isUnusualCurrency = currency !== defaultCurrency && currency !== "PGK";

    // Reset form when dialog opens/closes or existing line changes
    useEffect(() => {
        if (existingLine) {
            setDescription(existingLine.description);
            setAmount(existingLine.amount || "");
            setMinCharge(existingLine.min_charge || "");
            setCurrency(existingLine.currency);
            setUnitBasis(existingLine.unit_basis);
            setPercentage(existingLine.percentage || "");
            setPercentAppliesTo(existingLine.percent_applies_to || "BUCKET_FREIGHT");
            setTargetLineId(existingLine.target_line_id || "");
            setNotes(existingLine.notes || "");
            setDescriptionError(null);
        } else {
            setDescription("");
            setAmount("");
            setMinCharge("");
            setCurrency(defaultCurrency);
            setUnitBasis("PER_SHIPMENT");
            setPercentage("");
            setPercentAppliesTo("BUCKET_FREIGHT");
            setTargetLineId("");
            setNotes("");
            setDescriptionError(null);
        }
    }, [existingLine, open, defaultCurrency]);

    const isPercentage = unitBasis === "PERCENTAGE";
    const requiresTargetLine = isPercentage && percentAppliesTo === "SPECIFIC_LINE";

    // Available lines for specific line targeting (exclude self if editing)
    const availableTargetLines = existingLines.filter(
        (l) => l.unit_basis !== "PERCENTAGE" && l.id !== existingLine?.id
    );

    const handleDescriptionBlur = () => {
        const result = validateDescription(description);
        setDescriptionError(result.valid ? null : result.error || null);
    };

    const handleSave = () => {
        // Final validation check
        const descResult = validateDescription(description);
        if (!descResult.valid) {
            setDescriptionError(descResult.error || "Invalid description");
            return;
        }

        const line: SpotChargeLine = {
            id: existingLine?.id,
            bucket,
            description,
            amount: isPercentage ? null : amount,
            currency,
            unit_basis: unitBasis,
            min_charge: isPerKg && minCharge ? minCharge : null,
            percentage: isPercentage ? percentage : null,
            percent_applies_to: isPercentage ? percentAppliesTo : null,
            target_line_id: requiresTargetLine ? targetLineId : null,
            notes,
        };
        onSave(line);
        onClose();
    };

    const isValid = () => {
        const descResult = validateDescription(description);
        if (!descResult.valid) return false;

        if (isPercentage) {
            if (!percentage || parseFloat(percentage) <= 0) return false;
            if (requiresTargetLine && !targetLineId) return false;
        } else {
            if (!amount || parseFloat(amount) < 0) return false;
        }
        return true;
    };

    return (
        <Dialog open={open} onOpenChange={onClose}>
            <DialogContent className="sm:max-w-[500px]">
                <DialogHeader>
                    <DialogTitle>
                        {isEditing ? "Edit Charge Line" : "Add Charge Line"}
                    </DialogTitle>
                </DialogHeader>

                <div className="space-y-4 py-4">
                    {/* Description */}
                    <div className="space-y-2">
                        <Label htmlFor="description">Description *</Label>
                        <Input
                            id="description"
                            placeholder={DESCRIPTION_PLACEHOLDER}
                            value={description}
                            onChange={(e) => {
                                setDescription(e.target.value);
                                if (descriptionError) setDescriptionError(null);
                            }}
                            onBlur={handleDescriptionBlur}
                            className={descriptionError ? "border-destructive" : ""}
                        />
                        {descriptionError && (
                            <p className="text-sm text-destructive">{descriptionError}</p>
                        )}
                        <p className="text-xs text-muted-foreground">
                            Examples: &quot;Brisbane Delivery to 4000 CBD&quot;, &quot;Destination Terminal Fee (DXB)&quot;
                        </p>
                    </div>

                    {/* Unit Basis */}
                    <div className="space-y-2">
                        <Label>Unit Basis *</Label>
                        <Select value={unitBasis} onValueChange={(v) => setUnitBasis(v as SpotChargeUnitBasis)}>
                            <SelectTrigger>
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                {UNIT_BASIS_OPTIONS.map((opt) => (
                                    <SelectItem key={opt.value} value={opt.value}>
                                        {opt.label}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    {/* Amount + Currency (for non-percentage) */}
                    {!isPercentage && (
                        <div className="grid grid-cols-2 gap-3">
                            <div className="space-y-2">
                                <Label htmlFor="amount">Amount *</Label>
                                <Input
                                    id="amount"
                                    type="number"
                                    step="0.01"
                                    min="0"
                                    placeholder="0.00"
                                    value={amount}
                                    onChange={(e) => setAmount(e.target.value)}
                                />
                            </div>
                            <div className="space-y-2">
                                <Label className="flex items-center gap-1">
                                    Currency
                                    {isUnusualCurrency && (
                                        <AlertTriangle className="h-3.5 w-3.5 text-amber-500" />
                                    )}
                                </Label>
                                <Select value={currency} onValueChange={setCurrency}>
                                    <SelectTrigger className={isUnusualCurrency ? "border-amber-400" : ""}>
                                        <SelectValue />
                                    </SelectTrigger>
                                    <SelectContent>
                                        {CURRENCIES.map((c) => (
                                            <SelectItem key={c} value={c}>
                                                {c}
                                            </SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                                {isUnusualCurrency && (
                                    <p className="text-xs text-amber-600 flex items-center gap-1">
                                        <AlertTriangle className="h-3 w-3" />
                                        Unusual for this destination
                                    </p>
                                )}
                            </div>
                        </div>
                    )}

                    {/* Minimum Charge (for PER_KG only) */}
                    {isPerKg && !isPercentage && (
                        <div className="space-y-2">
                            <Label htmlFor="minCharge">Minimum Charge (optional)</Label>
                            <div className="flex items-center gap-2">
                                <Input
                                    id="minCharge"
                                    type="number"
                                    step="0.01"
                                    min="0"
                                    placeholder="e.g., 50.00"
                                    value={minCharge}
                                    onChange={(e) => setMinCharge(e.target.value)}
                                    className="flex-1"
                                />
                                <span className="text-sm text-muted-foreground">{currency}</span>
                            </div>
                            <p className="text-xs text-muted-foreground">
                                If rate × weight is less than this, the minimum will apply.
                            </p>
                        </div>
                    )}

                    {/* Percentage fields */}
                    {isPercentage && (
                        <>
                            <div className="grid grid-cols-2 gap-3">
                                <div className="space-y-2">
                                    <Label htmlFor="percentage">Percentage *</Label>
                                    <div className="relative">
                                        <Input
                                            id="percentage"
                                            type="number"
                                            step="0.01"
                                            min="0"
                                            placeholder="20"
                                            value={percentage}
                                            onChange={(e) => setPercentage(e.target.value)}
                                        />
                                        <span className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground">
                                            %
                                        </span>
                                    </div>
                                </div>
                                <div className="space-y-2">
                                    <Label>Applies To *</Label>
                                    <Select
                                        value={percentAppliesTo}
                                        onValueChange={(v) => setPercentAppliesTo(v as SpotChargePercentAppliesTo)}
                                    >
                                        <SelectTrigger>
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            {PERCENT_APPLIES_TO_OPTIONS.map((opt) => (
                                                <SelectItem key={opt.value} value={opt.value}>
                                                    {opt.label}
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>
                            </div>

                            {/* Target Line Selector */}
                            {requiresTargetLine && (
                                <div className="space-y-2">
                                    <Label>Target Charge Line *</Label>
                                    {availableTargetLines.length === 0 ? (
                                        <p className="text-sm text-amber-600">
                                            No charge lines available. Add a non-percentage charge first.
                                        </p>
                                    ) : (
                                        <Select value={targetLineId} onValueChange={setTargetLineId}>
                                            <SelectTrigger>
                                                <SelectValue placeholder="Select a charge line..." />
                                            </SelectTrigger>
                                            <SelectContent>
                                                {availableTargetLines.map((l) => (
                                                    <SelectItem key={l.id} value={l.id || ""}>
                                                        {l.description} ({l.amount} {l.currency})
                                                    </SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    )}
                                </div>
                            )}
                        </>
                    )}

                    {/* Notes */}
                    <div className="space-y-2">
                        <Label htmlFor="notes">Notes (optional)</Label>
                        <Textarea
                            id="notes"
                            placeholder="Any additional notes about this charge..."
                            value={notes}
                            onChange={(e) => setNotes(e.target.value)}
                            rows={2}
                        />
                    </div>
                </div>

                <DialogFooter>
                    <Button variant="outline" onClick={onClose}>
                        Cancel
                    </Button>
                    <Button onClick={handleSave} disabled={!isValid()}>
                        {isEditing ? "Update" : "Add"} Charge
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import {
    Card,
    CardContent,
    CardHeader,
    CardTitle,
    CardDescription,
} from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { Plus, Edit, Trash2 } from 'lucide-react';
import {
    getSpotRates,
    deleteSpotRate,
    deleteSpotCharge,
    type SpotRate,
    type SpotCharge,
} from '@/lib/api';
import { CreateSpotRateDialog } from './CreateSpotRateDialog';
import { SpotChargeDialog } from './SpotChargeDialog';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';

interface SpotRateManagerProps {
    quoteId: string;
    originLocationId: string;
    destinationLocationId: string;
    mode: string;
}

export function SpotRateManager({
    quoteId,
    originLocationId,
    destinationLocationId,
    mode,
}: SpotRateManagerProps) {
    const [spotRates, setSpotRates] = useState<SpotRate[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [isCreateDialogOpen, setIsCreateDialogOpen] = useState(false);
    const [isChargeDialogOpen, setIsChargeDialogOpen] = useState(false);
    const [selectedSpotRateId, setSelectedSpotRateId] = useState<string | null>(null);
    const [selectedCharge, setSelectedCharge] = useState<SpotCharge | null>(null);

    const fetchSpotRates = async () => {
        try {
            setLoading(true);
            setError(null);
            const data = await getSpotRates(quoteId);
            setSpotRates(data);
        } catch (err: unknown) {
            console.error(err);
            const message = err instanceof Error ? err.message : 'Failed to load spot rates';
            setError(message);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchSpotRates();
    }, [quoteId]);

    const handleCreateSpotRate = (newSpotRate: SpotRate) => {
        setSpotRates((prev) => [...prev, newSpotRate]);
    };

    const handleDeleteSpotRate = async (id: string) => {
        if (!confirm('Are you sure you want to delete this spot rate and all its charges?')) {
            return;
        }

        try {
            await deleteSpotRate(id);
            setSpotRates((prev) => prev.filter((sr) => sr.id !== id));
        } catch (err: unknown) {
            console.error(err);
            const message = err instanceof Error ? err.message : 'Failed to delete spot rate';
            alert(message);
        }
    };

    const handleAddCharge = (spotRateId: string) => {
        setSelectedSpotRateId(spotRateId);
        setSelectedCharge(null);
        setIsChargeDialogOpen(true);
    };

    const handleEditCharge = (spotRateId: string, charge: SpotCharge) => {
        setSelectedSpotRateId(spotRateId);
        setSelectedCharge(charge);
        setIsChargeDialogOpen(true);
    };

    const handleDeleteCharge = async (chargeId: string) => {
        if (!confirm('Are you sure you want to delete this charge?')) {
            return;
        }

        try {
            await deleteSpotCharge(chargeId);
            // Refresh spot rates to get updated charges
            fetchSpotRates();
        } catch (err: unknown) {
            console.error(err);
            const message = err instanceof Error ? err.message : 'Failed to delete charge';
            alert(message);
        }
    };

    const handleChargeSuccess = () => {
        fetchSpotRates();
    };

    if (loading) {
        return (
            <Card>
                <CardContent className="py-8 text-center text-muted-foreground">
                    Loading spot rates...
                </CardContent>
            </Card>
        );
    }

    return (
        <>
            <Card>
                <CardHeader>
                    <div className="flex items-center justify-between">
                        <div>
                            <CardTitle>Spot Rates</CardTitle>
                            <CardDescription>
                                Manual spot rates for this quote from specific suppliers
                            </CardDescription>
                        </div>
                        <Button onClick={() => setIsCreateDialogOpen(true)}>
                            <Plus className="w-4 h-4 mr-2" />
                            Add Spot Rate
                        </Button>
                    </div>
                </CardHeader>
                <CardContent>
                    {error && (
                        <Alert variant="destructive" className="mb-4">
                            <AlertTitle>Error</AlertTitle>
                            <AlertDescription>{error}</AlertDescription>
                        </Alert>
                    )}

                    {spotRates.length === 0 ? (
                        <div className="text-center py-8 text-muted-foreground">
                            No spot rates added yet. Click &quot;Add Spot Rate&quot; to begin.
                        </div>
                    ) : (
                        <div className="space-y-6">
                            {spotRates.map((spotRate) => (
                                <div key={spotRate.id} className="border rounded-lg p-4">
                                    <div className="flex items-start justify-between mb-4">
                                        <div>
                                            <div className="flex items-center gap-2">
                                                <h3 className="text-lg font-semibold">
                                                    {spotRate.supplier_name || 'Supplier'}
                                                </h3>
                                                <Badge variant="outline">{spotRate.currency}</Badge>
                                            </div>
                                            <p className="text-sm text-muted-foreground">
                                                {spotRate.origin_location_name || spotRate.origin_location} →{' '}
                                                {spotRate.destination_location_name || spotRate.destination_location}
                                            </p>
                                            {spotRate.valid_until && (
                                                <p className="text-xs text-muted-foreground mt-1">
                                                    Valid until: {spotRate.valid_until}
                                                </p>
                                            )}
                                            {spotRate.notes && (
                                                <p className="text-xs text-muted-foreground mt-1">
                                                    {spotRate.notes}
                                                </p>
                                            )}
                                        </div>
                                        <div className="flex gap-2">
                                            <Button
                                                variant="outline"
                                                size="sm"
                                                onClick={() => handleAddCharge(spotRate.id)}
                                            >
                                                <Plus className="w-4 h-4 mr-1" />
                                                Add Charge
                                            </Button>
                                            <Button
                                                variant="ghost"
                                                size="sm"
                                                onClick={() => handleDeleteSpotRate(spotRate.id)}
                                            >
                                                <Trash2 className="w-4 h-4" />
                                            </Button>
                                        </div>
                                    </div>

                                    {spotRate.charges && spotRate.charges.length > 0 ? (
                                        <Table>
                                            <TableHeader>
                                                <TableRow>
                                                    <TableHead>Component</TableHead>
                                                    <TableHead>Method</TableHead>
                                                    <TableHead className="text-right">Rate</TableHead>
                                                    <TableHead className="text-right">Min Charge</TableHead>
                                                    <TableHead className="text-right">Actions</TableHead>
                                                </TableRow>
                                            </TableHeader>
                                            <TableBody>
                                                {spotRate.charges.map((charge) => (
                                                    <TableRow key={charge.id}>
                                                        <TableCell>
                                                            <div className="font-medium">{charge.component_code}</div>
                                                            {charge.description && (
                                                                <div className="text-xs text-muted-foreground">
                                                                    {charge.description}
                                                                </div>
                                                            )}
                                                        </TableCell>
                                                        <TableCell>
                                                            <Badge variant="outline">{charge.method}</Badge>
                                                            {charge.unit && (
                                                                <span className="ml-2 text-xs text-muted-foreground">
                                                                    / {charge.unit}
                                                                </span>
                                                            )}
                                                        </TableCell>
                                                        <TableCell className="text-right">
                                                            {charge.method === 'PERCENT'
                                                                ? `${Number(charge.percent_value) * 100}%`
                                                                : charge.rate}
                                                        </TableCell>
                                                        <TableCell className="text-right">{charge.min_charge}</TableCell>
                                                        <TableCell className="text-right">
                                                            <div className="flex justify-end gap-2">
                                                                <Button
                                                                    variant="ghost"
                                                                    size="sm"
                                                                    onClick={() => handleEditCharge(spotRate.id, charge)}
                                                                >
                                                                    <Edit className="w-4 h-4" />
                                                                </Button>
                                                                <Button
                                                                    variant="ghost"
                                                                    size="sm"
                                                                    onClick={() => charge.id && handleDeleteCharge(charge.id)}
                                                                >
                                                                    <Trash2 className="w-4 h-4 text-destructive" />
                                                                </Button>
                                                            </div>
                                                        </TableCell>
                                                    </TableRow>
                                                ))}
                                            </TableBody>
                                        </Table>
                                    ) : (
                                        <div className="text-sm text-muted-foreground text-center py-4 border-t">
                                            No charges added yet
                                        </div>
                                    )}
                                </div>
                            ))}
                        </div>
                    )}
                </CardContent>
            </Card>

            <CreateSpotRateDialog
                isOpen={isCreateDialogOpen}
                onClose={() => setIsCreateDialogOpen(false)}
                onSuccess={handleCreateSpotRate}
                quoteId={quoteId}
                originLocationId={originLocationId}
                destinationLocationId={destinationLocationId}
                mode={mode}
            />

            {selectedSpotRateId && (
                <SpotChargeDialog
                    isOpen={isChargeDialogOpen}
                    onClose={() => setIsChargeDialogOpen(false)}
                    onSuccess={handleChargeSuccess}
                    spotRateId={selectedSpotRateId}
                    initialData={selectedCharge}
                />
            )}
        </>
    );
}

"use client";

/**
 * AssertionReviewCard - Interactive table for reviewing/classifying assertions
 * 
 * Features:
 * - Add/edit/remove assertions
 * - Change status (Confirmed/Conditional/Implicit/Missing)
 * - Shows warnings for missing mandatory fields
 * - Summary of assertion counts
 */

import { useState } from "react";
import { Plus, Trash2, AlertTriangle, CheckCircle2, AlertCircle, HelpCircle, XCircle } from "lucide-react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Badge } from "@/components/ui/badge";
import type {
    ReplyAnalysisResult,
    ExtractedAssertion,
    AssertionStatus,
    AssertionCategory,
} from "@/lib/spot-types";
import {
    STATUS_LABELS,
    STATUS_COLORS,
    CATEGORY_LABELS,
    MANDATORY_CATEGORIES,
} from "@/lib/spot-types";

interface AssertionReviewCardProps {
    result: ReplyAnalysisResult;
    onUpdate?: (result: ReplyAnalysisResult) => void;
    onConfirm: (result: ReplyAnalysisResult) => void;
    onBack: () => void;
    isLoading?: boolean;
}

const STATUS_ICONS: Record<AssertionStatus, React.ReactNode> = {
    confirmed: <CheckCircle2 className="h-4 w-4 text-green-600" />,
    conditional: <AlertCircle className="h-4 w-4 text-amber-600" />,
    implicit: <HelpCircle className="h-4 w-4 text-orange-600" />,
    missing: <XCircle className="h-4 w-4 text-red-600" />,
};

const createEmptyAssertion = (): ExtractedAssertion => ({
    text: "",
    category: "rate",
    status: "confirmed",
    confidence: 1.0,
});

export function AssertionReviewCard({
    result,
    onUpdate,
    onConfirm,
    onBack,
    isLoading,
}: AssertionReviewCardProps) {
    const { assertions, summary, warnings } = result;

    const handleUpdate = (updatedAssertions: ExtractedAssertion[]) => {
        if (onUpdate) {
            onUpdate({ ...result, assertions: updatedAssertions });
        }
    };

    const addAssertion = () => {
        handleUpdate([...assertions, createEmptyAssertion()]);
    };

    const removeAssertion = (index: number) => {
        handleUpdate(assertions.filter((_, i) => i !== index));
    };

    const updateAssertion = (index: number, field: keyof ExtractedAssertion, value: string | number) => {
        handleUpdate(assertions.map((a, i) =>
            i === index ? { ...a, [field]: value } : a
        ));
    };

    // Separate warnings by severity (all are now informational for SPOT mode)
    const infoWarnings = warnings.filter(w => w.includes('⚠️') || w.includes('⛔'));

    return (
        <Card>
            <CardHeader className="pb-3">
                <div className="flex items-center justify-between">
                    <div>
                        <CardTitle className="text-lg">Review Assertions</CardTitle>
                        <CardDescription>
                            Classify extracted information from the agent reply
                        </CardDescription>
                    </div>

                    {/* Summary badges */}
                    <div className="flex gap-2">
                        {summary.confirmed_count > 0 && (
                            <Badge variant="outline" className="bg-green-50 text-green-700 border-green-300">
                                {summary.confirmed_count} Confirmed
                            </Badge>
                        )}
                        {summary.conditional_count > 0 && (
                            <Badge variant="outline" className="bg-amber-50 text-amber-700 border-amber-300">
                                {summary.conditional_count} Conditional
                            </Badge>
                        )}
                        {summary.implicit_count > 0 && (
                            <Badge variant="outline" className="bg-orange-50 text-orange-700 border-orange-300">
                                {summary.implicit_count} Implicit
                            </Badge>
                        )}
                        {summary.missing_count > 0 && (
                            <Badge variant="outline" className="bg-red-50 text-red-700 border-red-300">
                                {summary.missing_count} Missing
                            </Badge>
                        )}
                    </div>
                </div>
            </CardHeader>

            <CardContent className="space-y-4">
                {/* Info warnings - all warnings are informational for SPOT mode */}
                {infoWarnings.length > 0 && (
                    <Alert className="bg-amber-50 border-amber-200">
                        <AlertCircle className="h-4 w-4 text-amber-600" />
                        <AlertDescription className="text-amber-700">
                            <ul className="list-disc list-inside">
                                {infoWarnings.map((w, i) => (
                                    <li key={i}>{w.replace('⚠️ ', '').replace('⛔ ', '')}</li>
                                ))}
                            </ul>
                        </AlertDescription>
                    </Alert>
                )}

                {/* Assertions table */}
                <div className="space-y-3">
                    {assertions.map((assertion, index) => (
                        <div
                            key={index}
                            className={`p-3 rounded-lg border ${STATUS_COLORS[assertion.status]}`}
                        >
                            <div className="grid grid-cols-12 gap-3 items-start">
                                {/* Status icon */}
                                <div className="col-span-1 flex justify-center pt-2">
                                    {STATUS_ICONS[assertion.status]}
                                </div>

                                {/* Text */}
                                <div className="col-span-4">
                                    <Input
                                        value={assertion.text}
                                        onChange={(e) => updateAssertion(index, 'text', e.target.value)}
                                        placeholder="e.g., USD 10.20/kg"
                                        className="bg-white"
                                    />
                                </div>

                                {/* Category */}
                                <div className="col-span-3">
                                    <Select
                                        value={assertion.category}
                                        onValueChange={(v) => updateAssertion(index, 'category', v)}
                                    >
                                        <SelectTrigger className="bg-white">
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            {Object.entries(CATEGORY_LABELS).map(([value, label]) => (
                                                <SelectItem key={value} value={value}>
                                                    {MANDATORY_CATEGORIES.includes(value as AssertionCategory) && (
                                                        <span className="text-red-500 mr-1">*</span>
                                                    )}
                                                    {label}
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>

                                {/* Status */}
                                <div className="col-span-3">
                                    <Select
                                        value={assertion.status}
                                        onValueChange={(v) => updateAssertion(index, 'status', v)}
                                    >
                                        <SelectTrigger className="bg-white">
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            {Object.entries(STATUS_LABELS).map(([value, label]) => (
                                                <SelectItem key={value} value={value}>
                                                    {label}
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>

                                {/* Remove */}
                                <div className="col-span-1">
                                    <Button
                                        variant="ghost"
                                        size="icon"
                                        onClick={() => removeAssertion(index)}
                                        className="text-red-500 hover:text-red-700"
                                    >
                                        <Trash2 className="h-4 w-4" />
                                    </Button>
                                </div>
                            </div>

                            {/* Additional fields for rate/charge categories */}
                            {['rate', 'origin_charges', 'dest_charges'].includes(assertion.category) && (
                                <div className="grid grid-cols-12 gap-3 mt-2 ml-8">
                                    <div className="col-span-2">
                                        <Input
                                            type="number"
                                            step="0.01"
                                            placeholder={assertion.rate_unit === 'min_or_per_kg' ? 'Min' : 'Amount'}
                                            value={assertion.rate_amount || ''}
                                            onChange={(e) => updateAssertion(index, 'rate_amount' as keyof ExtractedAssertion, e.target.value)}
                                            className="bg-white text-sm"
                                        />
                                    </div>
                                    {/* Show Per KG rate field for MIN_OR_PER_KG unit */}
                                    {assertion.rate_unit === 'min_or_per_kg' && (
                                        <div className="col-span-2">
                                            <Input
                                                type="number"
                                                step="0.01"
                                                placeholder="Per KG"
                                                value={assertion.rate_per_unit || ''}
                                                onChange={(e) => updateAssertion(index, 'rate_per_unit' as keyof ExtractedAssertion, e.target.value)}
                                                className="bg-white text-sm"
                                            />
                                        </div>
                                    )}
                                    <div className="col-span-2">
                                        <Select
                                            value={assertion.rate_currency || 'SGD'}
                                            onValueChange={(v) => updateAssertion(index, 'rate_currency' as keyof ExtractedAssertion, v)}
                                        >
                                            <SelectTrigger className="bg-white text-sm">
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="SGD">SGD</SelectItem>
                                                <SelectItem value="USD">USD</SelectItem>
                                                <SelectItem value="AUD">AUD</SelectItem>
                                                <SelectItem value="PGK">PGK</SelectItem>
                                                <SelectItem value="NZD">NZD</SelectItem>
                                                <SelectItem value="HKD">HKD</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <div className="col-span-2">
                                        <Select
                                            value={assertion.rate_unit || 'per_shipment'}
                                            onValueChange={(v) => updateAssertion(index, 'rate_unit' as keyof ExtractedAssertion, v)}
                                        >
                                            <SelectTrigger className="bg-white text-sm">
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="per_kg">Per KG</SelectItem>
                                                <SelectItem value="per_shipment">Per Shpt</SelectItem>
                                                <SelectItem value="per_awb">Per AWB</SelectItem>
                                                <SelectItem value="min_or_per_kg">Min or Per KG</SelectItem>
                                                <SelectItem value="percentage">Percentage</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                </div>
                            )}

                            {/* Validity date for validity category */}
                            {assertion.category === 'validity' && (
                                <div className="grid grid-cols-12 gap-3 mt-2 ml-8">
                                    <div className="col-span-4">
                                        <Input
                                            type="date"
                                            value={assertion.validity_date || ''}
                                            onChange={(e) => updateAssertion(index, 'validity_date' as keyof ExtractedAssertion, e.target.value)}
                                            className="bg-white text-sm"
                                        />
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}

                    {/* Add button */}
                    <Button
                        variant="outline"
                        onClick={addAssertion}
                        className="w-full"
                    >
                        <Plus className="h-4 w-4 mr-2" />
                        Add Assertion
                    </Button>
                </div>

                {/* Proceed and Back buttons */}
                <div className="pt-4 border-t flex gap-3">
                    <Button
                        variant="outline"
                        onClick={onBack}
                        className="w-1/3"
                        size="lg"
                    >
                        Back
                    </Button>
                    <Button
                        onClick={() => onConfirm(result)}
                        disabled={isLoading}
                        className="w-2/3"
                        size="lg"
                    >
                        Proceed to Rate Entry
                    </Button>
                </div>
            </CardContent>
        </Card>
    );
}

"use client";

/**
 * SpotEmailDraftCard - Generate SPOT rate request email draft
 * 
 * HARD RULES:
 * - No send button
 * - No email integration
 * - No auto-send or auto-copy
 * - One action only: Copy to Clipboard
 */

import { useState, useMemo, useEffect } from "react";
import { Copy, Check, Mail, AlertTriangle, Search, User } from "lucide-react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { searchCompanies, getContactsForCompany } from "@/lib/api";
import type { CompanySearchResult, Contact } from "@/lib/types";
import type { SPECommodity } from "@/lib/spot-types";

interface SpotEmailDraftCardProps {
    originCode: string;
    destinationCode: string;
    commodity: SPECommodity;
    weightKg: number;
    pieces: number;
    dimensions?: {
        pieces: number;
        length_cm: number;
        width_cm: number;
        height_cm: number;
        gross_weight_kg: number;
    }[];
    triggerCode?: string;
    userName?: string;
    serviceScope?: string;
    shipmentType?: "EXPORT" | "IMPORT" | "DOMESTIC";
}

// Commodity display names
const COMMODITY_NAMES: Record<string, string> = {
    'GCR': 'General Cargo',
    'DG': 'Dangerous Goods',
    'PER': 'Perishables',
    'AVI': 'Live Animals',
    'HVC': 'High Value Cargo',
    'HUM': 'Human Remains',
    'OOG': 'Oversized/Heavy',
    'VUL': 'Vulnerable Cargo',
    'TTS': 'Time/Temperature Sensitive',
    'SCR': 'Special Cargo',
};

export function SpotEmailDraftCard({
    originCode,
    destinationCode,
    commodity,
    weightKg,
    pieces,
    dimensions,
    triggerCode,
    userName = "",
    serviceScope,
    shipmentType,
}: SpotEmailDraftCardProps) {
    const [recipientName, setRecipientName] = useState("");
    const [pickupAddress, setPickupAddress] = useState("");
    const [deliveryAddress, setDeliveryAddress] = useState("");
    const [copied, setCopied] = useState(false);

    // Search state
    const [matchingCompanies, setMatchingCompanies] = useState<CompanySearchResult[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const [showSuggestions, setShowSuggestions] = useState(false);

    // Search for companies when recipient name changes
    useEffect(() => {
        const timer = setTimeout(async () => {
            if (recipientName.trim().length >= 2 && showSuggestions) {
                setIsSearching(true);
                try {
                    const results = await searchCompanies(recipientName);
                    setMatchingCompanies(results);
                } catch (err) {
                    console.error("Company search failed:", err);
                } finally {
                    setIsSearching(false);
                }
            } else {
                setMatchingCompanies([]);
            }
        }, 500);

        return () => clearTimeout(timer);
    }, [recipientName, showSuggestions]);

    const handleSelectCompany = (company: CompanySearchResult) => {
        setRecipientName(company.name);
        setMatchingCompanies([]);
        setShowSuggestions(false);
    };

    // Generate email draft
    const { subject, body } = useMemo(() => {
        const sender = userName.trim() || "Commercial Team";
        const recipient = recipientName.trim() || "[Agent / Carrier Name]";
        const commodityDisplay = COMMODITY_NAMES[commodity] || commodity;

        // Build dimensions text
        let dimensionsText = "";
        if (dimensions && dimensions.length > 0) {
            dimensions.forEach((dim) => {
                dimensionsText += `  - ${dim.pieces}x: ${dim.length_cm}×${dim.width_cm}×${dim.height_cm} cm, ${dim.gross_weight_kg} kg\n`;
            });
        } else {
            dimensionsText = `  - ${pieces} piece(s), ${weightKg} kg total\n`;
        }

        // Build conditional notes
        const notes: string[] = [];
        if (commodity === 'DG') {
            notes.push("This shipment is Dangerous Goods. Please advise acceptance and surcharges.");
        } else if (['PER', 'AVI', 'TTS'].includes(commodity)) {
            notes.push("This shipment requires special handling. Please advise conditions.");
        } else if (['HVC', 'VUL'].includes(commodity)) {
            notes.push("This shipment contains high-value/vulnerable cargo. Please advise security requirements.");
        } else if (commodity === 'OOG') {
            notes.push("This shipment is oversized. Please advise dimensional constraints and surcharges.");
        } else if (commodity === 'HUM') {
            notes.push("This shipment contains human remains. Please advise handling requirements.");
        }

        if (triggerCode === 'MULTI_LEG_ROUTING') {
            notes.push("If multiple legs apply, please quote per leg.");
        }

        const notesText = notes.length > 0 ? "\n" + notes.join("\n") + "\n" : "";

        // Determine address label logic
        let addressBlock = "";
        const showPickupInBody = serviceScope?.toUpperCase().trim().startsWith("D") || pickupAddress.trim().length > 0;
        const showDeliveryInBody = serviceScope?.toUpperCase().trim().endsWith("D") || deliveryAddress.trim().length > 0;

        if (showPickupInBody) {
            addressBlock += `Pickup Address: ${pickupAddress.trim() || "[Enter Pickup Address]"}\n`;
        }
        if (showDeliveryInBody) {
            addressBlock += `Delivery Address: ${deliveryAddress.trim() || "[Enter Delivery Address]"}\n`;
        }

        const subject = `SPOT Rate Request – ${originCode} → ${destinationCode} – ${weightKg}kg Airfreight`;

        const body = `Hi ${recipient},

Please provide a SPOT airfreight rate for the shipment below:

Origin: ${originCode}
Destination: ${destinationCode}
Commodity: ${commodityDisplay}
Weight: ${weightKg} kg
Pieces / Dimensions:
${dimensionsText.trimEnd()}
${notesText.trim()}
${addressBlock.trim()}

Thank you,
${sender}`;

        return { subject: subject.trim(), body: body.trim() };
    }, [
        originCode, destinationCode, commodity, weightKg, pieces, dimensions,
        triggerCode, userName, recipientName, serviceScope, shipmentType,
        pickupAddress, deliveryAddress
    ]);

    // Copy to clipboard
    const handleCopy = async () => {
        const fullEmail = `Subject: ${subject}\n\n${body}`;
        try {
            await navigator.clipboard.writeText(fullEmail);
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        } catch (err) {
            console.error("Failed to copy:", err);
        }
    };

    // Show both address inputs to ensure the user can find them
    const showPickupInput = true;
    const showDeliveryInput = true;

    return (
        <Card className="border-slate-200">
            <CardHeader className="pb-3">
                <CardTitle className="text-lg flex items-center gap-2">
                    <Mail className="h-5 w-5 text-slate-600" />
                    SPOT Rate Request Email
                </CardTitle>
                <CardDescription>
                    Copy this email draft to request rates from agents or carriers.
                </CardDescription>
            </CardHeader>

            <CardContent className="space-y-4">
                {/* Disclaimer */}
                <Alert className="bg-amber-50 border-amber-200">
                    <AlertTriangle className="h-4 w-4 text-amber-600" />
                    <AlertDescription className="text-amber-700 text-sm">
                        This is a draft only. No email will be sent automatically.
                    </AlertDescription>
                </Alert>

                {/* Recipient Input with DB Search */}
                <div className="grid grid-cols-1 gap-4">
                    <div className="relative">
                        <Label htmlFor="recipient" className="text-xs">Agent / Airline Contact (Search Customer Records)</Label>
                        <div className="relative mt-1">
                            <Input
                                id="recipient"
                                placeholder="Search by name..."
                                value={recipientName}
                                onChange={(e) => {
                                    setRecipientName(e.target.value);
                                    setShowSuggestions(true);
                                }}
                                onFocus={() => setShowSuggestions(true)}
                                className="pl-9"
                            />
                            <Search className="absolute left-3 top-2.5 h-4 w-4 text-muted-foreground" />
                            {isSearching && (
                                <div className="absolute right-3 top-2.5">
                                    <div className="animate-spin h-4 w-4 border-2 border-primary border-t-transparent rounded-full" />
                                </div>
                            )}
                        </div>

                        {/* Suggestions Dropdown */}
                        {showSuggestions && matchingCompanies.length > 0 && (
                            <div className="absolute z-10 w-full mt-1 bg-white border border-slate-200 rounded-md shadow-lg max-h-60 overflow-auto">
                                {matchingCompanies.map((company) => (
                                    <button
                                        key={company.id}
                                        className="w-full text-left px-4 py-2 text-sm hover:bg-slate-50 border-b last:border-0 border-slate-100"
                                        onClick={() => handleSelectCompany(company)}
                                    >
                                        <span className="font-medium">{company.name}</span>
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>
                </div>

                {/* Address Inputs */}
                {(showPickupInput || showDeliveryInput) && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {showPickupInput && (
                            <div>
                                <Label htmlFor="pickup" className="text-xs">Pickup Address</Label>
                                <Input
                                    id="pickup"
                                    placeholder="Enter pickup suburb/postcode"
                                    value={pickupAddress}
                                    onChange={(e) => setPickupAddress(e.target.value)}
                                    className="mt-1"
                                />
                            </div>
                        )}
                        {showDeliveryInput && (
                            <div>
                                <Label htmlFor="delivery" className="text-xs">Delivery Address</Label>
                                <Input
                                    id="delivery"
                                    placeholder="Enter delivery suburb/postcode"
                                    value={deliveryAddress}
                                    onChange={(e) => setDeliveryAddress(e.target.value)}
                                    className="mt-1"
                                />
                            </div>
                        )}
                    </div>
                )}

                {/* Subject line */}
                <div>
                    <Label className="text-xs text-muted-foreground">Subject</Label>
                    <div className="mt-1 p-2 bg-slate-50 rounded border text-sm font-mono">
                        {subject}
                    </div>
                </div>

                {/* Email body */}
                <div>
                    <Label className="text-xs text-muted-foreground">Email Body</Label>
                    <Textarea
                        value={body}
                        readOnly
                        rows={16}
                        className="mt-1 font-mono text-sm bg-slate-50 resize-none"
                    />
                </div>

                {/* Copy button - THE ONLY ACTION */}
                <Button
                    onClick={handleCopy}
                    className="w-full"
                    variant={copied ? "outline" : "default"}
                >
                    {copied ? (
                        <>
                            <Check className="h-4 w-4 mr-2 text-green-600" />
                            Copied to Clipboard
                        </>
                    ) : (
                        <>
                            <Copy className="h-4 w-4 mr-2" />
                            Copy to Clipboard
                        </>
                    )}
                </Button>
            </CardContent>
        </Card>
    );
}

// frontend/src/hooks/use-spot-mode.ts
/**
 * SPOT Mode State Machine Hook
 * 
 * Manages the SPOT Mode flow state based on backend evaluation.
 * Provides actions for each step: scope check, trigger eval, SPE lifecycle.
 */

import { useState, useCallback, useMemo } from 'react';
import type {
    SpotFlowState,
    SpotModeState,
    TriggerResult,
    TriggerEvaluateRequest,
    CreateSPERequest,
    SpotPricingEnvelope,
    SPEComputeRequest,
    SPEComputeResponse,
} from '@/lib/spot-types';
import {
    validateSpotScope,
    evaluateSpotTrigger,
    createSpotEnvelope,
    updateSpotEnvelope,
    getSpotEnvelope,
    acknowledgeSpotEnvelope,
    approveSpotEnvelope,
    computeSpotQuote,
    createSpotQuote,
} from '@/lib/api';

const initialState: SpotModeState = {
    flowState: 'NORMAL',
    spe: null,
    triggerResult: null,
    error: null,
    isLoading: false,
    quoteResult: null,
};

const resolveSpotFlowState = (spe: SpotPricingEnvelope): SpotFlowState => {
    if (spe.is_expired || spe.status === 'expired') {
        return 'EXPIRED';
    }
    if (spe.status === 'rejected') {
        return 'REVIEW';
    }
    if (spe.status === 'ready' || spe.acknowledgement) {
        return 'READY';
    }
    if (spe.charges.length > 0 || spe.missing_mandatory_fields.length > 0) {
        return 'REVIEW';
    }
    return 'INTAKE';
};

/**
 * useSpotMode - Custom hook for managing SPOT Mode flow
 * 
 * Usage:
 * ```tsx
 * const { state, actions } = useSpotMode();
 * 
 * // Step 1: Check scope
 * const inScope = await actions.checkScope('AU', 'PG');
 * if (!inScope) return; // OUT_OF_SCOPE
 * 
 * // Step 2: Evaluate trigger
 * const isSpot = await actions.evaluateTrigger({ ... });
 * if (!isSpot) return; // NORMAL flow
 * 
 * // Step 3+: SPOT flow continues...
 * ```
 */
export function useSpotMode() {
    const [state, setState] = useState<SpotModeState>(initialState);

    // Helper to update state
    const updateState = useCallback((updates: Partial<SpotModeState>) => {
        setState(prev => ({ ...prev, ...updates }));
    }, []);

    // ==========================================================================
    // STEP 1: Scope Validation
    // ==========================================================================
    const checkScope = useCallback(async (
        originCountry: string,
        destinationCountry: string
    ): Promise<boolean> => {
        updateState({ isLoading: true, error: null });

        try {
            const result = await validateSpotScope({
                origin_country: originCountry,
                destination_country: destinationCountry,
            });

            if (!result.is_valid) {
                updateState({
                    flowState: 'OUT_OF_SCOPE',
                    error: result.error,
                    isLoading: false,
                });
                return false;
            }

            updateState({ isLoading: false });
            return true;
        } catch (err) {
            updateState({
                error: err instanceof Error ? err.message : 'Scope validation failed',
                isLoading: false,
            });
            return false;
        }
    }, [updateState]);

    // ==========================================================================
    // STEP 2: Trigger Evaluation
    // ==========================================================================
    const evaluateTrigger = useCallback(async (
        request: TriggerEvaluateRequest
    ): Promise<boolean> => {
        updateState({ isLoading: true, error: null });

        try {
            const result = await evaluateSpotTrigger(request);

            if (result.is_spot_required) {
                updateState({
                    flowState: 'SPOT_REQUIRED',
                    triggerResult: result.trigger,
                    isLoading: false,
                });
                return true;
            }

            updateState({
                flowState: 'NORMAL',
                isLoading: false,
            });
            return false;
        } catch (err) {
            updateState({
                error: err instanceof Error ? err.message : 'Trigger evaluation failed',
                isLoading: false,
            });
            return false;
        }
    }, [updateState]);

    // ==========================================================================
    // STEP 3: Create SPE
    // ==========================================================================
    const createSPE = useCallback(async (
        request: CreateSPERequest
    ): Promise<SpotPricingEnvelope | null> => {
        updateState({ isLoading: true, error: null });

        try {
            const spe = await createSpotEnvelope(request);
            updateState({
                flowState: resolveSpotFlowState(spe),
                spe,
                isLoading: false,
            });
            return spe;
        } catch (err) {
            updateState({
                error: err instanceof Error ? err.message : 'Failed to create SPE',
                isLoading: false,
            });
            return null;
        }
    }, [updateState]);

    // ==========================================================================
    // STEP 3.5: Update SPE (Draft)
    // ==========================================================================
    const updateSPE = useCallback(async (
        id: string,
        data: { charges?: Omit<import('@/lib/spot-types').SPEChargeLine, 'id'>[]; conditions?: Partial<import('@/lib/spot-types').SPEConditions> }
    ): Promise<SpotPricingEnvelope | null> => {
        updateState({ isLoading: true, error: null });

        try {
            const spe = await updateSpotEnvelope(id, data);
            updateState({
                flowState: resolveSpotFlowState(spe),
                spe,
                isLoading: false,
            });
            return spe;
        } catch (err) {
            updateState({
                error: err instanceof Error ? err.message : 'Failed to update SPE',
                isLoading: false,
            });
            return null;
        }
    }, [updateState]);

    // ==========================================================================
    // Load SPE by ID
    // ==========================================================================
    const loadSPE = useCallback(async (
        id: string
    ): Promise<SpotPricingEnvelope | null> => {
        updateState({ isLoading: true, error: null });

        try {
            const spe = await getSpotEnvelope(id);

            // Determine flow state from SPE status
            const flowState = resolveSpotFlowState(spe);

            updateState({
                flowState,
                spe,
                triggerResult: {
                    code: spe.spot_trigger_reason_code,
                    text: spe.spot_trigger_reason_text
                },
                isLoading: false,
            });
            return spe;
        } catch (err) {
            updateState({
                error: err instanceof Error ? err.message : 'Failed to load SPE',
                isLoading: false,
            });
            return null;
        }
    }, [updateState]);

    // ==========================================================================
    // STEP 4: Sales Acknowledgement
    // ==========================================================================
    const submitAcknowledgement = useCallback(async (): Promise<boolean> => {
        if (!state.spe) {
            updateState({ error: 'No SPE loaded' });
            return false;
        }

        updateState({ isLoading: true, error: null });

        try {
            const result = await acknowledgeSpotEnvelope(state.spe.id);

            // Reload SPE to get updated state
            await loadSPE(state.spe.id);
            return result.success;
        } catch (err) {
            updateState({
                error: err instanceof Error ? err.message : 'Acknowledgement failed',
                isLoading: false,
            });
            return false;
        }
    }, [state.spe, updateState, loadSPE]);

    // ==========================================================================
    // STEP 5: Manager Approval
    // ==========================================================================
    const submitManagerApproval = useCallback(async (
        approved: boolean,
        comment?: string
    ): Promise<boolean> => {
        if (!state.spe) {
            updateState({ error: 'No SPE loaded' });
            return false;
        }

        updateState({ isLoading: true, error: null });

        try {
            const result = await approveSpotEnvelope(state.spe.id, approved, comment);

            // Reload SPE to get updated state
            await loadSPE(state.spe.id);

            return result.approved;
        } catch (err) {
            updateState({
                error: err instanceof Error ? err.message : 'Approval failed',
                isLoading: false,
            });
            return false;
        }
    }, [state.spe, updateState, loadSPE]);

    // ==========================================================================
    // STEP 6: Compute SPOT Quote
    // ==========================================================================
    const computeQuote = useCallback(async (
        request: SPEComputeRequest
    ): Promise<SPEComputeResponse | null> => {
        if (!state.spe) {
            updateState({ error: 'No SPE loaded' });
            return null;
        }

        updateState({ isLoading: true, error: null });

        try {
            const result = await computeSpotQuote(state.spe.id, request);

            if (!result.is_complete) {
                updateState({
                    error: result.reason || 'Quote computation incomplete',
                    isLoading: false,
                });
                return result;
            }

            updateState({
                isLoading: false,
                quoteResult: result,
            });
            return result;
        } catch (err) {
            updateState({
                error: err instanceof Error ? err.message : 'Quote computation failed',
                isLoading: false,
            });
            return null;
        }
    }, [state.spe, updateState]);

    // ==========================================================================
    // STEP 7: Create Final Quote
    // ==========================================================================
    const createQuote = useCallback(async (
        request: {
            payment_term: string;
            service_scope: string;
            output_currency: string;
            customer_id?: string;
        }
    ): Promise<{ success: boolean; quote_id: string } | null> => {
        if (!state.spe) return null;
        updateState({ isLoading: true, error: null });
        try {
            const result = await createSpotQuote(state.spe.id, request);
            updateState({ isLoading: false });
            return result;
        } catch (err) {
            updateState({
                error: err instanceof Error ? err.message : 'Failed to create quote',
                isLoading: false,
            });
            return null;
        }
    }, [state.spe, updateState]);

    // ==========================================================================
    // Reset
    // ==========================================================================
    const reset = useCallback(() => {
        setState(initialState);
    }, []);

    // ==========================================================================
    // Derived state
    // ==========================================================================
    const canProceedToPricing =
        state.spe !== null &&
        state.spe.status === 'ready' &&
        state.spe.can_proceed &&
        !state.spe.is_expired;

    const blockedReason = (() => {
        if (state.flowState === 'OUT_OF_SCOPE') {
            return state.error || 'Shipment is out of scope';
        }
        if (state.flowState === 'EXPIRED') {
            return 'SPE has expired - please create a new one';
        }
        if (state.spe?.status === 'rejected') {
            return state.spe.manager_approval?.comment || 'Manager rejected this quote';
        }
        if (state.flowState === 'REVIEW' && state.spe && !state.spe.acknowledgement) {
            return 'Acknowledgement required';
        }
        return null;
    })();

    const actions = useMemo(() => ({
        checkScope,
        evaluateTrigger,
        createSPE,
        updateSPE,
        loadSPE,
        submitAcknowledgement,
        submitManagerApproval,
        computeQuote,
        createQuote,
        reset,
    }), [
        checkScope,
        evaluateTrigger,
        createSPE,
        updateSPE,
        loadSPE,
        submitManagerApproval,
        computeQuote,
        createQuote,
        reset
    ]);

    const derived = useMemo(() => ({
        canProceedToPricing,
        blockedReason,
    }), [canProceedToPricing, blockedReason]);

    return {
        state,
        actions,
        derived,
    };
}
